#include "biblia.h"

void Biblia::CarregarAtos(Biblia* b) {
    b->dados[ATOS].nome = wxT("Atos");

    b->dados[ATOS].capitulos[1].versos[1] = wxT("Fiz o primeiro tratado, ó Teófilo, acerca de tudo quanto Jesus começou a fazer e ensinar,");
    b->dados[ATOS].capitulos[1].versos[2] = wxT("até o dia em que foi levado para cima, depois de haver dado mandamento, pelo Espírito Santo, aos apóstolos que escolhera;");
    b->dados[ATOS].capitulos[1].versos[3] = wxT("aos quais também, depois de haver padecido, se apresentou vivo, com muitas provas infalíveis, aparecendo-lhes por espaço de quarenta dias, e lhes falando das coisas concernentes ao reino de Deus.");
    b->dados[ATOS].capitulos[1].versos[4] = wxT("Estando com eles, ordenou-lhes que não se ausentassem de Jerusalém, mas que esperassem a promessa do Pai, a qual {disse ele} de mim ouvistes.");
    b->dados[ATOS].capitulos[1].versos[5] = wxT("Porque, na verdade, João batizou em água, mas vós sereis batizados no Espírito Santo, dentro de poucos dias.");
    b->dados[ATOS].capitulos[1].versos[6] = wxT("Aqueles, pois, que se haviam reunido perguntavam-lhe, dizendo: Senhor, é nesse tempo que restauras o reino a Israel?");
    b->dados[ATOS].capitulos[1].versos[7] = wxT("Respondeu-lhes: A vós não vos compete saber os tempos ou as épocas, que o Pai reservou à sua própria autoridade.");
    b->dados[ATOS].capitulos[1].versos[8] = wxT("Mas recebereis poder, ao descer sobre vós o Espírito Santo, e ser-me-eis testemunhas, tanto em Jerusalém, como em toda a Judéia e Samária, e até os confins da terra.");
    b->dados[ATOS].capitulos[1].versos[9] = wxT("Tendo ele dito estas coisas, foi levado para cima, enquanto eles olhavam, e uma nuvem o recebeu, ocultando-o a seus olhos.");
    b->dados[ATOS].capitulos[1].versos[10] = wxT("Estando eles com os olhos fitos no céu, enquanto ele subia, eis que junto deles apareceram dois varões vestidos de branco,");
    b->dados[ATOS].capitulos[1].versos[11] = wxT("os quais lhes disseram: Varões galileus, por que ficais aí olhando para o céu? Esse Jesus, que dentre vós foi elevado para o céu, há de vir assim como para o céu o vistes ir.");
    b->dados[ATOS].capitulos[1].versos[12] = wxT("Então voltaram para Jerusalém, do monte chamado das Oliveiras, que está perto de Jerusalém, à distância da jornada de um sábado.");
    b->dados[ATOS].capitulos[1].versos[13] = wxT("E, entrando, subiram ao cenáculo, onde permaneciam Pedro e João, Tiago e André, Felipe e Tomé, Bartolomeu e Mateus; Tiago, filho de Alfeu, Simão o Zelote, e Judas, filho de Tiago.");
    b->dados[ATOS].capitulos[1].versos[14] = wxT("Todos estes perseveravam unanimemente em oração, com as mulheres, e Maria, mãe de Jesus, e com os irmãos dele.");
    b->dados[ATOS].capitulos[1].versos[15] = wxT("Naqueles dias levantou-se Pedro no meio dos irmãos, sendo o número de pessoas ali reunidas cerca de cento e vinte, e disse:");
    b->dados[ATOS].capitulos[1].versos[16] = wxT("Irmãos, convinha que se cumprisse a escritura que o Espírito Santo predisse pela boca de Davi, acerca de Judas, que foi o guia daqueles que prenderam a Jesus;");
    b->dados[ATOS].capitulos[1].versos[17] = wxT("pois ele era contado entre nós e teve parte neste ministério.");
    b->dados[ATOS].capitulos[1].versos[18] = wxT("{Ora, ele adquiriu um campo com o salário da sua iniqüidade; e precipitando-se, caiu prostrado e arrebentou pelo meio, e todas as suas entranhas se derramaram.");
    b->dados[ATOS].capitulos[1].versos[19] = wxT("E tornou-se isto conhecido de todos os habitantes de Jerusalém; de maneira que na própria língua deles esse campo se chama Acéldama, isto é, Campo de Sangue.}");
    b->dados[ATOS].capitulos[1].versos[20] = wxT("Porquanto no livro dos Salmos está escrito: Fique deserta a sua habitação, e não haja quem nela habite; e: Tome outro o seu ministério.");
    b->dados[ATOS].capitulos[1].versos[21] = wxT("É necessário, pois, que dos varões que conviveram conosco todo o tempo em que o Senhor Jesus andou entre nós,");
    b->dados[ATOS].capitulos[1].versos[22] = wxT("começando desde o batismo de João até o dia em que dentre nós foi levado para cima, um deles se torne testemunha conosco da sua ressurreição.");
    b->dados[ATOS].capitulos[1].versos[23] = wxT("E apresentaram dois: José, chamado Barsabás, que tinha por sobrenome o Justo, e Matias.");
    b->dados[ATOS].capitulos[1].versos[24] = wxT("E orando, disseram: Tu, Senhor, que conheces os corações de todos, mostra qual destes dois tens escolhido");
    b->dados[ATOS].capitulos[1].versos[25] = wxT("para tomar o lugar neste ministério e apostolado, do qual Judas se desviou para ir ao seu próprio lugar.");
    b->dados[ATOS].capitulos[1].versos[26] = wxT("Então deitaram sortes a respeito deles e caiu a sorte sobre Matias, e por voto comum foi ele contado com os onze apóstolos.");

    b->dados[ATOS].capitulos[2].versos[1] = wxT("Ao cumprir-se o dia de Pentecostes, estavam todos reunidos no mesmo lugar.");
    b->dados[ATOS].capitulos[2].versos[2] = wxT("De repente veio do céu um ruído, como que de um vento impetuoso, e encheu toda a casa onde estavam sentados.");
    b->dados[ATOS].capitulos[2].versos[3] = wxT("E lhes apareceram umas línguas como que de fogo, que se distribuíam, e sobre cada um deles pousou uma.");
    b->dados[ATOS].capitulos[2].versos[4] = wxT("E todos ficaram cheios do Espírito Santo, e começaram a falar noutras línguas, conforme o Espírito lhes concedia que falassem.");
    b->dados[ATOS].capitulos[2].versos[5] = wxT("Habitavam então em Jerusalém judeus, homens piedosos, de todas as nações que há debaixo do céu.");
    b->dados[ATOS].capitulos[2].versos[6] = wxT("Ouvindo-se, pois, aquele ruído, ajuntou-se a multidão; e estava confusa, porque cada um os ouvia falar na sua própria língua.");
    b->dados[ATOS].capitulos[2].versos[7] = wxT("E todos pasmavam e se admiravam, dizendo uns aos outros: Pois quê! não são galileus todos esses que estão falando?");
    b->dados[ATOS].capitulos[2].versos[8] = wxT("Como é, pois, que os ouvimos falar cada um na própria língua em que nascemos?");
    b->dados[ATOS].capitulos[2].versos[9] = wxT("Nós, partos, medos, e elamitas; e os que habitamos a Mesopotâmia, a Judéia e a Capadócia, o Ponto e a Ásia,");
    b->dados[ATOS].capitulos[2].versos[10] = wxT("a Frígia e a Panfília, o Egito e as partes da Líbia próximas a Cirene, e forasteiros romanos, tanto judeus como prosélitos,");
    b->dados[ATOS].capitulos[2].versos[11] = wxT("cretenses e árabes-ouvímo-los em nossas línguas, falar das grandezas de Deus.");
    b->dados[ATOS].capitulos[2].versos[12] = wxT("E todos pasmavam e estavam perplexos, dizendo uns aos outros: Que quer dizer isto?");
    b->dados[ATOS].capitulos[2].versos[13] = wxT("E outros, zombando, diziam: Estão cheios de mosto.");
    b->dados[ATOS].capitulos[2].versos[14] = wxT("Então Pedro, pondo-se em pé com os onze, levantou a voz e disse-lhes: Varões judeus e todos os que habitais em Jerusalém, seja-vos isto notório, e escutai as minhas palavras.");
    b->dados[ATOS].capitulos[2].versos[15] = wxT("Pois estes homens não estão embriagados, como vós pensais, visto que é apenas a terceira hora do dia.");
    b->dados[ATOS].capitulos[2].versos[16] = wxT("Mas isto é o que foi dito pelo profeta Joel:");
    b->dados[ATOS].capitulos[2].versos[17] = wxT("E acontecerá nos últimos dias, diz o Senhor, que derramarei do meu Espírito sobre toda a carne; e os vossos filhos e as vossas filhas profetizarão, os vossos mancebos terão visões, os vossos anciãos terão sonhos;");
    b->dados[ATOS].capitulos[2].versos[18] = wxT("e sobre os meus servos e sobre as minhas servas derramarei do meu Espírito naqueles dias, e eles profetizarão.");
    b->dados[ATOS].capitulos[2].versos[19] = wxT("E mostrarei prodígios em cima no céu; e sinais embaixo na terra, sangue, fogo e vapor de fumaça.");
    b->dados[ATOS].capitulos[2].versos[20] = wxT("O sol se converterá em trevas, e a lua em sangue, antes que venha o grande e glorioso dia do Senhor.");
    b->dados[ATOS].capitulos[2].versos[21] = wxT("E acontecerá que todo aquele que invocar o nome do Senhor será salvo.");
    b->dados[ATOS].capitulos[2].versos[22] = wxT("Varões israelitas, escutai estas palavras: A Jesus, o nazareno, varão aprovado por Deus entre vós com milagres, prodígios e sinais, que Deus por ele fez no meio de vós, como vós mesmos bem sabeis;");
    b->dados[ATOS].capitulos[2].versos[23] = wxT("a este, que foi entregue pelo determinado conselho e presciência de Deus, vós matastes, crucificando-o pelas mãos de iníquos;");
    b->dados[ATOS].capitulos[2].versos[24] = wxT("ao qual Deus ressuscitou, rompendo os grilhões da morte, pois não era possível que fosse retido por ela.");
    b->dados[ATOS].capitulos[2].versos[25] = wxT("Porque dele fala Davi: Sempre via diante de mim o Senhor, porque está à minha direita, para que eu não seja abalado;");
    b->dados[ATOS].capitulos[2].versos[26] = wxT("por isso se alegrou o meu coração, e a minha língua exultou; e além disso a minha carne há de repousar em esperança;");
    b->dados[ATOS].capitulos[2].versos[27] = wxT("pois não deixarás a minha alma no inferno, nem permitirás que o teu Santo veja a corrupção;");
    b->dados[ATOS].capitulos[2].versos[28] = wxT("fizeste-me conhecer os caminhos da vida; encher-me-ás de alegria na tua presença.");
    b->dados[ATOS].capitulos[2].versos[29] = wxT("Irmãos, seja-me permitido dizer-vos livremente acerca do patriarca Davi, que ele morreu e foi sepultado, e entre nós está até hoje a sua sepultura.");
    b->dados[ATOS].capitulos[2].versos[30] = wxT("Sendo, pois, ele profeta, e sabendo que Deus lhe havia prometido com juramento que faria sentar sobre o seu trono um dos seus descendentes,");
    b->dados[ATOS].capitulos[2].versos[31] = wxT("prevendo isto, Davi falou da ressurreição de Cristo, que a sua alma não foi deixada no inferno, nem a sua carne viu a corrupção.");
    b->dados[ATOS].capitulos[2].versos[32] = wxT("Ora, a este Jesus, Deus ressuscitou, do que todos nós somos testemunhas.");
    b->dados[ATOS].capitulos[2].versos[33] = wxT("De sorte que, exaltado pela destra de Deus, e tendo recebido do Pai a promessa do Espírito Santo, derramou isto que vós agora vedes e ouvis.");
    b->dados[ATOS].capitulos[2].versos[34] = wxT("Porque Davi não subiu aos céus, mas ele próprio declara: Disse o Senhor ao meu Senhor: Assenta-te à minha direita,");
    b->dados[ATOS].capitulos[2].versos[35] = wxT("até que eu ponha os teus inimigos por escabelo de teus pés.");
    b->dados[ATOS].capitulos[2].versos[36] = wxT("Saiba pois com certeza toda a casa de Israel que a esse mesmo Jesus, a quem vós crucificastes, Deus o fez Senhor e Cristo.");
    b->dados[ATOS].capitulos[2].versos[37] = wxT("E, ouvindo eles isto, compungiram-se em seu coração, e perguntaram a Pedro e aos demais apóstolos: Que faremos, irmãos?");
    b->dados[ATOS].capitulos[2].versos[38] = wxT("Pedro então lhes respondeu: Arrependei-vos, e cada um de vós seja batizado em nome de Jesus Cristo, para remissão de vossos pecados; e recebereis o dom do Espírito Santo.");
    b->dados[ATOS].capitulos[2].versos[39] = wxT("Porque a promessa vos pertence a vós, a vossos filhos, e a todos os que estão longe: a quantos o Senhor nosso Deus chamar.");
    b->dados[ATOS].capitulos[2].versos[40] = wxT("E com muitas outras palavras dava testemunho, e os exortava, dizendo: salvai-vos desta geração perversa.");
    b->dados[ATOS].capitulos[2].versos[41] = wxT("De sorte que foram batizados os que receberam a sua palavra; e naquele dia agregaram-se quase três mil almas;");
    b->dados[ATOS].capitulos[2].versos[42] = wxT("e perseveravam na doutrina dos apóstolos e na comunhão, no partir do pão e nas orações.");
    b->dados[ATOS].capitulos[2].versos[43] = wxT("Em cada alma havia temor, e muitos prodígios e sinais eram feitos pelos apóstolos.");
    b->dados[ATOS].capitulos[2].versos[44] = wxT("Todos os que criam estavam unidos e tinham tudo em comum.");
    b->dados[ATOS].capitulos[2].versos[45] = wxT("E vendiam suas propriedades e bens e os repartiam por todos, segundo a necessidade de cada um.");
    b->dados[ATOS].capitulos[2].versos[46] = wxT("E, perseverando unânimes todos os dias no templo, e partindo o pão em casa, comiam com alegria e singeleza de coração,");
    b->dados[ATOS].capitulos[2].versos[47] = wxT("louvando a Deus, e caindo na graça de todo o povo. E cada dia acrescentava-lhes o Senhor os que iam sendo salvos.");

    b->dados[ATOS].capitulos[3].versos[1] = wxT("Pedro e João subiam ao templo à hora da oração, a nona.");
    b->dados[ATOS].capitulos[3].versos[2] = wxT("E, era carregado um homem, coxo de nascença, o qual todos os dias punham à porta do templo, chamada Formosa, para pedir esmolas aos que entravam.");
    b->dados[ATOS].capitulos[3].versos[3] = wxT("Ora, vendo ele a Pedro e João, que iam entrando no templo, pediu que lhe dessem uma esmola.");
    b->dados[ATOS].capitulos[3].versos[4] = wxT("E Pedro, com João, fitando os olhos nele, disse: Olha para nós.");
    b->dados[ATOS].capitulos[3].versos[5] = wxT("E ele os olhava atentamente, esperando receber deles alguma coisa.");
    b->dados[ATOS].capitulos[3].versos[6] = wxT("Disse-lhe Pedro: Não tenho prata nem ouro; mas o que tenho, isso te dou; em nome de Jesus Cristo, o nazareno, anda.");
    b->dados[ATOS].capitulos[3].versos[7] = wxT("Nisso, tomando-o pela mão direita, o levantou; imediatamente os seus pés e artelhos se firmaram");
    b->dados[ATOS].capitulos[3].versos[8] = wxT("e, dando ele um salto, pôs-se em pé. Começou a andar e entrou com eles no templo, andando, saltando e louvando a Deus.");
    b->dados[ATOS].capitulos[3].versos[9] = wxT("Todo o povo, ao vê-lo andar e louvar a Deus,");
    b->dados[ATOS].capitulos[3].versos[10] = wxT("reconhecia-o como o mesmo que estivera sentado a pedir esmola à Porta Formosa do templo; e todos ficaram cheios de pasmo e assombro, pelo que lhe acontecera.");
    b->dados[ATOS].capitulos[3].versos[11] = wxT("Apegando-se o homem a Pedro e João, todo o povo correu atônito para junto deles, ao pórtico chamado de Salomão.");
    b->dados[ATOS].capitulos[3].versos[12] = wxT("Pedro, vendo isto, disse ao povo: Varões israelitas, por que vos admirais deste homem? Ou, por que fitais os olhos em nós, como se por nosso próprio poder ou piedade o tivéssemos feito andar?");
    b->dados[ATOS].capitulos[3].versos[13] = wxT("O Deus de Abraão, de Isaque e de Jacó, o Deus de nossos pais, glorificou a seu Servo Jesus, a quem vós entregastes e perante a face de Pilatos negastes, quando este havia resolvido soltá-lo.");
    b->dados[ATOS].capitulos[3].versos[14] = wxT("Mas vós negastes o Santo e Justo, e pedistes que se vos desse um homicida;");
    b->dados[ATOS].capitulos[3].versos[15] = wxT("e matastes o Autor da vida, a quem Deus ressuscitou dentre os mortos, do que nós somos testemunhas.");
    b->dados[ATOS].capitulos[3].versos[16] = wxT("E pela fé em seu nome fez o seu nome fortalecer a este homem que vedes e conheceis; sim, a fé, que vem por ele, deu a este, na presença de todos vós, esta perfeita saúde.");
    b->dados[ATOS].capitulos[3].versos[17] = wxT("Agora, irmãos, eu sei que o fizestes por ignorância, como também as vossas autoridades.");
    b->dados[ATOS].capitulos[3].versos[18] = wxT("Mas Deus assim cumpriu o que já dantes pela boca de todos os seus profetas havia anunciado que o seu Cristo havia de padecer.");
    b->dados[ATOS].capitulos[3].versos[19] = wxT("Arrependei-vos, pois, e convertei-vos, para que sejam apagados os vossos pecados, de sorte que venham os tempos de refrigério, da presença do Senhor,");
    b->dados[ATOS].capitulos[3].versos[20] = wxT("e envie ele o Cristo, que já dantes vos foi indicado, Jesus,");
    b->dados[ATOS].capitulos[3].versos[21] = wxT("ao qual convém que o céu receba até os tempos da restauração de todas as coisas, das quais Deus falou pela boca dos seus santos profetas, desde o princípio.");
    b->dados[ATOS].capitulos[3].versos[22] = wxT("Pois Moisés disse: Suscitar-vos-á o Senhor vosso Deus, dentre vossos irmãos, um profeta semelhante a mim; a ele ouvireis em tudo quanto vos disser.");
    b->dados[ATOS].capitulos[3].versos[23] = wxT("E acontecerá que toda alma que não ouvir a esse profeta, será exterminada dentre o povo.");
    b->dados[ATOS].capitulos[3].versos[24] = wxT("E todos os profetas, desde Samuel e os que sucederam, quantos falaram, também anunciaram estes dias.");
    b->dados[ATOS].capitulos[3].versos[25] = wxT("Vós sois os filhos dos profetas e do pacto que Deus fez com vossos pais, dizendo a Abraão: Na tua descendência serão abençoadas todas as famílias da terra.");
    b->dados[ATOS].capitulos[3].versos[26] = wxT("Deus suscitou a seu Servo, e a vós primeiramente vo-lo enviou para que vos abençoasse, desviando-vos, a cada um, das vossas maldades.");

    b->dados[ATOS].capitulos[4].versos[1] = wxT("Enquanto eles estavam falando ao povo, sobrevieram-lhes os sacerdotes, o capitão do templo e os saduceus,");
    b->dados[ATOS].capitulos[4].versos[2] = wxT("doendo-se muito de que eles ensinassem o povo, e anunciassem em Jesus a ressurreição dentre os mortos,");
    b->dados[ATOS].capitulos[4].versos[3] = wxT("deitaram mão neles, e os encerraram na prisão até o dia seguinte; pois era já tarde.");
    b->dados[ATOS].capitulos[4].versos[4] = wxT("Muitos, porém, dos que ouviram a palavra, creram, e se elevou o número dos homens a quase cinco mil.");
    b->dados[ATOS].capitulos[4].versos[5] = wxT("No dia seguinte, reuniram-se em Jerusalém as autoridades, os anciãos, os escribas,");
    b->dados[ATOS].capitulos[4].versos[6] = wxT("e Anás, o sumo sacerdote, e Caifás, João, Alexandre, e todos quantos eram da linhagem do sumo sacerdote.");
    b->dados[ATOS].capitulos[4].versos[7] = wxT("E, pondo-os no meio deles, perguntaram: Com que poder ou em nome de quem fizestes vós isto?");
    b->dados[ATOS].capitulos[4].versos[8] = wxT("Então Pedro, cheio do Espírito Santo, lhes disse: Autoridades do povo e vós, anciãos,");
    b->dados[ATOS].capitulos[4].versos[9] = wxT("se nós hoje somos inquiridos acerca do benefício feito a um enfermo, e do modo como foi curado,");
    b->dados[ATOS].capitulos[4].versos[10] = wxT("seja conhecido de vós todos, e de todo o povo de Israel, que em nome de Jesus Cristo, o nazareno, aquele a quem vós crucificastes e a quem Deus ressuscitou dentre os mortos, nesse nome está este aqui, são diante de vós.");
    b->dados[ATOS].capitulos[4].versos[11] = wxT("Ele é a pedra que foi rejeitada por vós, os edificadores, a qual foi posta como pedra angular.");
    b->dados[ATOS].capitulos[4].versos[12] = wxT("E em nenhum outro há salvação; porque debaixo do céu nenhum outro nome há, dado entre os homens, em que devamos ser salvos.");
    b->dados[ATOS].capitulos[4].versos[13] = wxT("Então eles, vendo a intrepidez de Pedro e João, e tendo percebido que eram homens iletrados e indoutos, se admiravam; e reconheciam que haviam estado com Jesus.");
    b->dados[ATOS].capitulos[4].versos[14] = wxT("E vendo em pé com eles o homem que fora curado, nada tinham que dizer em contrário.");
    b->dados[ATOS].capitulos[4].versos[15] = wxT("Todavia, mandando-os sair do sinédrio, conferenciaram entre si,");
    b->dados[ATOS].capitulos[4].versos[16] = wxT("dizendo: Que havemos de fazer a estes homens? porque a todos os que habitam em Jerusalém é manifesto que por eles foi feito um sinal notório, e não o podemos negar.");
    b->dados[ATOS].capitulos[4].versos[17] = wxT("Mas, para que não se divulgue mais entre o povo, ameacemo-los para que de ora em diante não falem neste nome a homem algum.");
    b->dados[ATOS].capitulos[4].versos[18] = wxT("E, chamando-os, ordenaram-lhes que absolutamente não falassem nem ensinassem em nome de Jesus.");
    b->dados[ATOS].capitulos[4].versos[19] = wxT("Mas Pedro e João, respondendo, lhes disseram: Julgai vós se é justo diante de Deus ouvir-nos antes a vós do que a Deus;");
    b->dados[ATOS].capitulos[4].versos[20] = wxT("pois nós não podemos deixar de falar das coisas que temos visto e ouvido.");
    b->dados[ATOS].capitulos[4].versos[21] = wxT("Mas eles ainda os ameaçaram mais, e, não achando motivo para os castigar, soltaram-nos, por causa do povo; porque todos glorificavam a Deus pelo que acontecera;");
    b->dados[ATOS].capitulos[4].versos[22] = wxT("pois tinha mais de quarenta anos o homem em quem se operara esta cura milagrosa.");
    b->dados[ATOS].capitulos[4].versos[23] = wxT("E soltos eles, foram para os seus, e contaram tudo o que lhes haviam dito os principais sacerdotes e os anciãos.");
    b->dados[ATOS].capitulos[4].versos[24] = wxT("Ao ouvirem isto, levantaram unanimemente a voz a Deus e disseram: Senhor, tu que fizeste o céu, a terra, o mar, e tudo o que neles há;");
    b->dados[ATOS].capitulos[4].versos[25] = wxT("que pelo Espírito Santo, por boca de nosso pai Davi, teu servo, disseste: Por que se enfureceram os gentios, e os povos imaginaram coisas vãs?");
    b->dados[ATOS].capitulos[4].versos[26] = wxT("Levantaram-se os reis da terra, e as autoridades ajuntaram-se à uma, contra o Senhor e contra o seu Ungido.");
    b->dados[ATOS].capitulos[4].versos[27] = wxT("Porque verdadeiramente se ajuntaram, nesta cidade, contra o teu santo Servo Jesus, ao qual ungiste, não só Herodes, mas também Pôncio Pilatos com os gentios e os povos de Israel;");
    b->dados[ATOS].capitulos[4].versos[28] = wxT("para fazerem tudo o que a tua mão e o teu conselho predeterminaram que se fizesse.");
    b->dados[ATOS].capitulos[4].versos[29] = wxT("Agora pois, ó Senhor, olha para as suas ameaças, e concede aos teus servos que falem com toda a intrepidez a tua palavra,");
    b->dados[ATOS].capitulos[4].versos[30] = wxT("enquanto estendes a mão para curar e para que se façam sinais e prodígios pelo nome de teu santo Servo Jesus.");
    b->dados[ATOS].capitulos[4].versos[31] = wxT("E, tendo eles orado, tremeu o lugar em que estavam reunidos; e todos foram cheios do Espírito Santo, e anunciavam com intrepidez a palavra de Deus.");
    b->dados[ATOS].capitulos[4].versos[32] = wxT("Da multidão dos que criam, era um só o coração e uma só a alma, e ninguém dizia que coisa alguma das que possuía era sua própria, mas todas as coisas lhes eram comuns.");
    b->dados[ATOS].capitulos[4].versos[33] = wxT("Com grande poder os apóstolos davam testemunho da ressurreição do Senhor Jesus, e em todos eles havia abundante graça.");
    b->dados[ATOS].capitulos[4].versos[34] = wxT("Pois não havia entre eles necessitado algum; porque todos os que possuíam terras ou casas, vendendo-as, traziam o preço do que vendiam e o depositavam aos pés dos apóstolos.");
    b->dados[ATOS].capitulos[4].versos[35] = wxT("E se repartia a qualquer um que tivesse necessidade.");
    b->dados[ATOS].capitulos[4].versos[36] = wxT("Então José, cognominado pelos apóstolos Barnabé {que quer dizer, filho de consolação}, levita, natural de Chipre,");
    b->dados[ATOS].capitulos[4].versos[37] = wxT("possuindo um campo, vendeu-o, trouxe o preço e o depositou aos pés dos apóstolos.");

    b->dados[ATOS].capitulos[5].versos[1] = wxT("Mas um certo homem chamado Ananias, com Safira, sua mulher, vendeu uma propriedade,");
    b->dados[ATOS].capitulos[5].versos[2] = wxT("e reteve parte do preço, sabendo-o também sua mulher; e levando a outra parte, a depositou aos pés dos apóstolos.");
    b->dados[ATOS].capitulos[5].versos[3] = wxT("Disse então Pedro: Ananias, por que encheu Satanás o teu coração, para que mentisses ao Espírito Santo e retivesses parte do preço do terreno?");
    b->dados[ATOS].capitulos[5].versos[4] = wxT("Enquanto o possuías, não era teu? e vendido, não estava o preço em teu poder? Como, pois, formaste este desígnio em teu coração? Não mentiste aos homens, mas a Deus.");
    b->dados[ATOS].capitulos[5].versos[5] = wxT("E Ananias, ouvindo estas palavras, caiu e expirou. E grande temor veio sobre todos os que souberam disto.");
    b->dados[ATOS].capitulos[5].versos[6] = wxT("Levantando-se os moços, cobriram-no e, transportando-o para fora, o sepultaram.");
    b->dados[ATOS].capitulos[5].versos[7] = wxT("Depois de um intervalo de cerca de três horas, entrou também sua mulher, não sabendo o que havia acontecido.");
    b->dados[ATOS].capitulos[5].versos[8] = wxT("E perguntou-lhe Pedro: Dize-me: Vendestes por tanto aquele terreno? E ela respondeu: Sim, por tanto.");
    b->dados[ATOS].capitulos[5].versos[9] = wxT("Então Pedro lhe disse: Por que é que combinastes entre vós provar o Espírito do Senhor? Eis aí à porta os pés dos que sepultaram o teu marido, e te levarão também a ti.");
    b->dados[ATOS].capitulos[5].versos[10] = wxT("Imediatamente ela caiu aos pés dele e expirou. E entrando os moços, acharam-na morta e, levando-a para fora, sepultaram-na ao lado do marido.");
    b->dados[ATOS].capitulos[5].versos[11] = wxT("Sobreveio grande temor a toda a igreja e a todos os que ouviram estas coisas.");
    b->dados[ATOS].capitulos[5].versos[12] = wxT("E muitos sinais e prodígios eram feitos entre o povo pelas mãos dos apóstolos. E estavam todos de comum acordo no pórtico de Salomão.");
    b->dados[ATOS].capitulos[5].versos[13] = wxT("Dos outros, porém, nenhum ousava ajuntar-se a eles; mas o povo os tinha em grande estima;");
    b->dados[ATOS].capitulos[5].versos[14] = wxT("e cada vez mais se agregavam crentes ao Senhor em grande número tanto de homens como de mulheres,");
    b->dados[ATOS].capitulos[5].versos[15] = wxT("a ponto de transportarem os enfermos para as ruas, e os porem em leitos e macas, para que ao passar Pedro, ao menos sua sombra cobrisse alguns deles.");
    b->dados[ATOS].capitulos[5].versos[16] = wxT("Também das cidades circunvizinhas afluía muita gente a Jerusalém, conduzindo enfermos e atormentados de espíritos imundos, os quais eram todos curados.");
    b->dados[ATOS].capitulos[5].versos[17] = wxT("Levantando-se o sumo sacerdote e todos os que estavam com ele {isto é, a seita dos saduceus}, encheram-se de inveja,");
    b->dados[ATOS].capitulos[5].versos[18] = wxT("deitaram mão nos apóstolos, e os puseram na prisão pública.");
    b->dados[ATOS].capitulos[5].versos[19] = wxT("Mas de noite um anjo do Senhor abriu as portas do cárcere e, tirando-os para fora, disse:");
    b->dados[ATOS].capitulos[5].versos[20] = wxT("Ide, apresentai-vos no templo, e falai ao povo todas as palavras desta vida.");
    b->dados[ATOS].capitulos[5].versos[21] = wxT("Ora, tendo eles ouvido isto, entraram de manhã cedo no templo e ensinavam. Chegando, porém o sumo sacerdote e os que estavam com ele, convocaram o sinédrio, com todos os anciãos dos filhos de Israel, e enviaram guardas ao cárcere para trazê-los.");
    b->dados[ATOS].capitulos[5].versos[22] = wxT("Mas os guardas, tendo lá ido, não os acharam na prisão; e voltando, lho anunciaram,");
    b->dados[ATOS].capitulos[5].versos[23] = wxT("dizendo: Achamos realmente o cárcere fechado com toda a segurança, e as sentinelas em pé às portas; mas, abrindo-as, a ninguém achamos dentro.");
    b->dados[ATOS].capitulos[5].versos[24] = wxT("E quando o capitão do templo e os principais sacerdotes ouviram estas palavras ficaram perplexos acerca deles e do que viria a ser isso.");
    b->dados[ATOS].capitulos[5].versos[25] = wxT("Então chegou alguém e lhes anunciou: Eis que os homens que encerrastes na prisão estão no templo, em pé, a ensinar o povo.");
    b->dados[ATOS].capitulos[5].versos[26] = wxT("Nisso foi o capitão com os guardas e os trouxe, não com violência, porque temiam ser apedrejados pelo povo.");
    b->dados[ATOS].capitulos[5].versos[27] = wxT("E tendo-os trazido, os apresentaram ao sinédrio. E o sumo sacerdote os interrogou, dizendo:");
    b->dados[ATOS].capitulos[5].versos[28] = wxT("Não vos admoestamos expressamente que não ensinásseis nesse nome? e eis que enchestes Jerusalém dessa vossa doutrina e quereis lançar sobre nós o sangue desse homem.");
    b->dados[ATOS].capitulos[5].versos[29] = wxT("Respondendo Pedro e os apóstolos, disseram: Importa antes obedecer a Deus que aos homens.");
    b->dados[ATOS].capitulos[5].versos[30] = wxT("O Deus de nossos pais ressuscitou a Jesus, ao qual vós matastes, suspendendo-o no madeiro;");
    b->dados[ATOS].capitulos[5].versos[31] = wxT("sim, Deus, com a sua destra, o elevou a Príncipe e Salvador, para dar a Israel o arrependimento e remissão de pecados.");
    b->dados[ATOS].capitulos[5].versos[32] = wxT("E nós somos testemunhas destas coisas, e bem assim o Espírito Santo, que Deus deu àqueles que lhe obedecem.");
    b->dados[ATOS].capitulos[5].versos[33] = wxT("Ora, ouvindo eles isto, se enfureceram e queriam matá-los.");
    b->dados[ATOS].capitulos[5].versos[34] = wxT("Mas, levantando-se no sinédrio certo fariseu chamado Gamaliel, doutor da lei, acatado por todo o povo, mandou que por um pouco saíssem aqueles homens;");
    b->dados[ATOS].capitulos[5].versos[35] = wxT("e prosseguiu: Varões israelitas, acautelai-vos a respeito do que estais para fazer a estes homens.");
    b->dados[ATOS].capitulos[5].versos[36] = wxT("Porque, há algum tempo, levantou-se Teudas, dizendo ser alguém; ao qual se ajuntaram uns quatrocentos homens; mas ele foi morto, e todos quantos lhe obedeciam foram dispersos e reduzidos a nada.");
    b->dados[ATOS].capitulos[5].versos[37] = wxT("Depois dele levantou-se Judas, o galileu, nos dias do recenseamento, e levou muitos após si; mas também este pereceu, e todos quantos lhe obedeciam foram dispersos.");
    b->dados[ATOS].capitulos[5].versos[38] = wxT("Agora vos digo: Dai de mão a estes homens, e deixai-os, porque este conselho ou esta obra, caso seja dos homens, se desfará;");
    b->dados[ATOS].capitulos[5].versos[39] = wxT("mas, se é de Deus, não podereis derrotá-los; para que não sejais, porventura, achados até combatendo contra Deus.");
    b->dados[ATOS].capitulos[5].versos[40] = wxT("Concordaram, pois, com ele, e tendo chamado os apóstolos, açoitaram-nos e mandaram que não falassem em nome de Jesus, e os soltaram.");
    b->dados[ATOS].capitulos[5].versos[41] = wxT("Retiraram-se pois da presença do sinédrio, regozijando-se de terem sido julgados dignos de sofrer afronta pelo nome de Jesus.");
    b->dados[ATOS].capitulos[5].versos[42] = wxT("E todos os dias, no templo e de casa em casa, não cessavam de ensinar, e de anunciar a Jesus, o Cristo.");

    b->dados[ATOS].capitulos[6].versos[1] = wxT("Ora, naqueles dias, crescendo o número dos discípulos, houve uma murmuração dos helenistas contra os hebreus, porque as viúvas daqueles estavam sendo esquecidas na distribuição diária.");
    b->dados[ATOS].capitulos[6].versos[2] = wxT("E os doze, convocando a multidão dos discípulos, disseram: Não é razoável que nós deixemos a palavra de Deus e sirvamos às mesas.");
    b->dados[ATOS].capitulos[6].versos[3] = wxT("Escolhei, pois, irmãos, dentre vós, sete homens de boa reputação, cheios do Espírito Santo e de sabedoria, aos quais encarreguemos deste serviço.");
    b->dados[ATOS].capitulos[6].versos[4] = wxT("Mas nós perseveraremos na oração e no ministério da palavra.");
    b->dados[ATOS].capitulos[6].versos[5] = wxT("O parecer agradou a todos, e elegeram a Estevão, homem cheio de fé e do Espírito Santo, Filipe, Prócoro, Nicanor, Timão, Pármenas, e Nicolau, prosélito de Antioquia,");
    b->dados[ATOS].capitulos[6].versos[6] = wxT("e os apresentaram perante os apóstolos; estes, tendo orado, lhes impuseram as mãos.");
    b->dados[ATOS].capitulos[6].versos[7] = wxT("E divulgava-se a palavra de Deus, de sorte que se multiplicava muito o número dos discípulos em Jerusalém e muitos sacerdotes obedeciam à fé.");
    b->dados[ATOS].capitulos[6].versos[8] = wxT("Ora, Estêvão, cheio de graça e poder, fazia prodígios e grandes sinais entre o povo.");
    b->dados[ATOS].capitulos[6].versos[9] = wxT("Levantaram-se, porém, alguns que eram da sinagoga chamada dos libertos, dos cireneus, dos alexandrinos, dos da Cilícia e da Ásia, e disputavam com Estêvão;");
    b->dados[ATOS].capitulos[6].versos[10] = wxT("e não podiam resistir à sabedoria e ao Espírito com que falava.");
    b->dados[ATOS].capitulos[6].versos[11] = wxT("Então subornaram uns homens para que dissessem: Temo-lo ouvido proferir palavras blasfemas contra Moisés e contra Deus.");
    b->dados[ATOS].capitulos[6].versos[12] = wxT("Assim excitaram o povo, os anciãos, e os escribas; e investindo contra ele, o arrebataram e o levaram ao sinédrio;");
    b->dados[ATOS].capitulos[6].versos[13] = wxT("e apresentaram falsas testemunhas que diziam: Este homem não cessa de proferir palavras contra este santo lugar e contra a lei;");
    b->dados[ATOS].capitulos[6].versos[14] = wxT("porque nós o temos ouvido dizer que esse Jesus, o nazareno, há de destruir este lugar e mudar os costumes que Moisés nos transmitiu.");
    b->dados[ATOS].capitulos[6].versos[15] = wxT("Então todos os que estavam assentados no sinédrio, fitando os olhos nele, viram o seu rosto como de um anjo.");

    b->dados[ATOS].capitulos[7].versos[1] = wxT("E disse o sumo sacerdote: Porventura são assim estas coisas?");
    b->dados[ATOS].capitulos[7].versos[2] = wxT("Estêvão respondeu: Irmãos e pais, ouvi. O Deus da glória apareceu a nosso pai Abraão, estando ele na Mesopotâmia, antes de habitar em Harã,");
    b->dados[ATOS].capitulos[7].versos[3] = wxT("e disse-lhe: Sai da tua terra e dentre a tua parentela, e dirige-te à terra que eu te mostrar.");
    b->dados[ATOS].capitulos[7].versos[4] = wxT("Então saiu da terra dos caldeus e habitou em Harã. Dali, depois que seu pai faleceu, Deus o trouxe para esta terra em que vós agora habitais.");
    b->dados[ATOS].capitulos[7].versos[5] = wxT("E não lhe deu nela herança, nem sequer o espaço de um pé; mas prometeu que lha daria em possessão, e depois dele à sua descendência, não tendo ele ainda filho.");
    b->dados[ATOS].capitulos[7].versos[6] = wxT("Pois Deus disse que a sua descendência seria peregrina em terra estranha e que a escravizariam e maltratariam por quatrocentos anos.");
    b->dados[ATOS].capitulos[7].versos[7] = wxT("Mas eu julgarei a nação que os tiver escravizado, disse Deus; e depois disto sairão, e me servirão neste lugar.");
    b->dados[ATOS].capitulos[7].versos[8] = wxT("E deu-lhe o pacto da circuncisão; assim então gerou Abraão a Isaque, e o circuncidou ao oitavo dia; e Isaque gerou a Jacó, e Jacó aos doze patriarcas.");
    b->dados[ATOS].capitulos[7].versos[9] = wxT("Os patriarcas, movidos de inveja, venderam José para o Egito; mas Deus era com ele,");
    b->dados[ATOS].capitulos[7].versos[10] = wxT("e o livrou de todas as suas tribulações, e lhe deu graça e sabedoria perante Faraó, rei do Egito, que o constituiu governador sobre o Egito e toda a sua casa.");
    b->dados[ATOS].capitulos[7].versos[11] = wxT("Sobreveio então uma fome a todo o Egito e Canaã, e grande tribulação; e nossos pais não achavam alimentos.");
    b->dados[ATOS].capitulos[7].versos[12] = wxT("Mas tendo ouvido Jacó que no Egito havia trigo, enviou ali nossos pais pela primeira vez.");
    b->dados[ATOS].capitulos[7].versos[13] = wxT("E na segunda vez deu-se José a conhecer a seus irmãos, e a sua linhagem tornou-se manifesta a Faraó.");
    b->dados[ATOS].capitulos[7].versos[14] = wxT("Então José mandou chamar a seu pai Jacó, e a toda a sua parentela-setenta e cinco almas.");
    b->dados[ATOS].capitulos[7].versos[15] = wxT("Jacó, pois, desceu ao Egito, onde morreu, ele e nossos pais;");
    b->dados[ATOS].capitulos[7].versos[16] = wxT("e foram transportados para Siquém e depositados na sepultura que Abraão comprara por certo preço em prata aos filhos de Emor, em Siquém.");
    b->dados[ATOS].capitulos[7].versos[17] = wxT("Enquanto se aproximava o tempo da promessa que Deus tinha feito a Abraão, o povo crescia e se multiplicava no Egito;");
    b->dados[ATOS].capitulos[7].versos[18] = wxT("até que se levantou ali outro rei, que não tinha conhecido José.");
    b->dados[ATOS].capitulos[7].versos[19] = wxT("Usando esse de astúcia contra a nossa raça, maltratou a nossos pais, ao ponto de fazê-los enjeitar seus filhos, para que não vivessem.");
    b->dados[ATOS].capitulos[7].versos[20] = wxT("Nesse tempo nasceu Moisés, e era mui formoso, e foi criado três meses em casa de seu pai.");
    b->dados[ATOS].capitulos[7].versos[21] = wxT("Sendo ele enjeitado, a filha de Faraó o recolheu e o criou como seu próprio filho.");
    b->dados[ATOS].capitulos[7].versos[22] = wxT("Assim Moisés foi instruído em toda a sabedoria dos egípcios, e era poderoso em palavras e obras.");
    b->dados[ATOS].capitulos[7].versos[23] = wxT("Ora, quando ele completou quarenta anos, veio-lhe ao coração visitar seus irmãos, os filhos de Israel.");
    b->dados[ATOS].capitulos[7].versos[24] = wxT("E vendo um deles sofrer injustamente, defendeu-o, e vingou o oprimido, matando o egípcio.");
    b->dados[ATOS].capitulos[7].versos[25] = wxT("Cuidava que seus irmãos entenderiam que por mão dele Deus lhes havia de dar a liberdade; mas eles não entenderam.");
    b->dados[ATOS].capitulos[7].versos[26] = wxT("No dia seguinte apareceu-lhes quando brigavam, e quis levá-los à paz, dizendo: Homens, sois irmãos; por que vos maltratais um ao outro?");
    b->dados[ATOS].capitulos[7].versos[27] = wxT("Mas o que fazia injustiça ao seu próximo o repeliu, dizendo: Quem te constituiu senhor e juiz sobre nós?");
    b->dados[ATOS].capitulos[7].versos[28] = wxT("Acaso queres tu matar-me como ontem mataste o egípcio?");
    b->dados[ATOS].capitulos[7].versos[29] = wxT("A esta palavra fugiu Moisés, e tornou-se peregrino na terra de Madiã, onde gerou dois filhos.");
    b->dados[ATOS].capitulos[7].versos[30] = wxT("E passados mais quarenta anos, apareceu-lhe um anjo no deserto do monte Sinai, numa chama de fogo no meio de uma sarça.");
    b->dados[ATOS].capitulos[7].versos[31] = wxT("Moisés, vendo isto, admirou-se da visão; e, aproximando-se ele para observar, soou a voz do Senhor:");
    b->dados[ATOS].capitulos[7].versos[32] = wxT("Eu sou o deus de teus pais, o Deus de Abraão, de Isaque e de Jacó. E Moisés ficou trêmulo e não ousava olhar.");
    b->dados[ATOS].capitulos[7].versos[33] = wxT("Disse-lhe então o Senhor: Tira as alparcas dos teus pés, porque o lugar em que estás é terra santa.");
    b->dados[ATOS].capitulos[7].versos[34] = wxT("Vi, com efeito, a aflição do meu povo no Egito, ouvi os seus gemidos, e desci para livrá-lo. Agora pois vem, e enviar-te-ei ao Egito.");
    b->dados[ATOS].capitulos[7].versos[35] = wxT("A este Moisés que eles haviam repelido, dizendo: Quem te constituiu senhor e juiz? a este enviou Deus como senhor e libertador, pela mão do anjo que lhe aparecera na sarça.");
    b->dados[ATOS].capitulos[7].versos[36] = wxT("Foi este que os conduziu para fora, fazendo prodígios e sinais na terra do Egito, e no Mar Vermelho, e no deserto por quarenta anos.");
    b->dados[ATOS].capitulos[7].versos[37] = wxT("Este é o Moisés que disse aos filhos de Israel: Deus vos suscitará dentre vossos irmãos um profeta como eu.");
    b->dados[ATOS].capitulos[7].versos[38] = wxT("Este é o que esteve na congregação no deserto, com o anjo que lhe falava no monte Sinai, e com nossos pais, o qual recebeu palavras de vida para vo-las dar;");
    b->dados[ATOS].capitulos[7].versos[39] = wxT("ao qual os nossos pais não quiseram obedecer, antes o rejeitaram, e em seus corações voltaram ao Egito,");
    b->dados[ATOS].capitulos[7].versos[40] = wxT("dizendo a Arão: Faze-nos deuses que vão adiante de nós; porque a esse Moisés que nos tirou da terra do Egito, não sabemos o que lhe aconteceu.");
    b->dados[ATOS].capitulos[7].versos[41] = wxT("Fizeram, pois, naqueles dias o bezerro, e ofereceram sacrifício ao ídolo, e se alegravam nas obras das suas mãos.");
    b->dados[ATOS].capitulos[7].versos[42] = wxT("Mas Deus se afastou, e os abandonou ao culto das hostes do céu, como está escrito no livro dos profetas: Porventura me oferecestes vítimas e sacrifícios por quarenta anos no deserto, ó casa de Israel?");
    b->dados[ATOS].capitulos[7].versos[43] = wxT("Antes carregastes o tabernáculo de Moloque e a estrela do deus Renfã, figuras que vós fizestes para adorá-las. Desterrar-vos-ei pois, para além da Babilônia.");
    b->dados[ATOS].capitulos[7].versos[44] = wxT("Entre os nossos pais no deserto estava o tabernáculo do testemunho, como ordenara aquele que disse a Moisés que o fizesse segundo o modelo que tinha visto;");
    b->dados[ATOS].capitulos[7].versos[45] = wxT("o qual nossos pais, tendo-o por sua vez recebido, o levaram sob a direção de Josué, quando entraram na posse da terra das nações que Deus expulsou da presença dos nossos pais, até os dias de Davi,");
    b->dados[ATOS].capitulos[7].versos[46] = wxT("que achou graça diante de Deus, e pediu que lhe fosse dado achar habitação para o Deus de Jacó.");
    b->dados[ATOS].capitulos[7].versos[47] = wxT("Entretanto foi Salomão quem lhe edificou uma casa;");
    b->dados[ATOS].capitulos[7].versos[48] = wxT("mas o Altíssimo não habita em templos feitos por mãos de homens, como diz o profeta:");
    b->dados[ATOS].capitulos[7].versos[49] = wxT("O céu é meu trono, e a terra o escabelo dos meus pés. Que casa me edificareis, diz o Senhor, ou qual o lugar do meu repouso?");
    b->dados[ATOS].capitulos[7].versos[50] = wxT("Não fez, porventura, a minha mão todas estas coisas?");
    b->dados[ATOS].capitulos[7].versos[51] = wxT("Homens de dura cerviz, e incircuncisos de coração e ouvido, vós sempre resistis ao Espírito Santo; como o fizeram os vossos pais, assim também vós.");
    b->dados[ATOS].capitulos[7].versos[52] = wxT("A qual dos profetas não perseguiram vossos pais? Até mataram os que dantes anunciaram a vinda do Justo, do qual vós agora vos tornastes traidores e homicidas,");
    b->dados[ATOS].capitulos[7].versos[53] = wxT("vós, que recebestes a lei por ordenação dos anjos, e não a guardastes.");
    b->dados[ATOS].capitulos[7].versos[54] = wxT("Ouvindo eles isto, enfureciam-se em seus corações, e rangiam os dentes contra Estêvão.");
    b->dados[ATOS].capitulos[7].versos[55] = wxT("Mas ele, cheio do Espírito Santo, fitando os olhos no céu, viu a glória de Deus, e Jesus em pé à direita de Deus,");
    b->dados[ATOS].capitulos[7].versos[56] = wxT("e disse: Eis que vejo os céus abertos, e o Filho do homem em pé à direita de Deus.");
    b->dados[ATOS].capitulos[7].versos[57] = wxT("Então eles gritaram com grande voz, taparam os ouvidos, e arremeteram unânimes contra ele");
    b->dados[ATOS].capitulos[7].versos[58] = wxT("e, lançando-o fora da cidade, o apedrejavam. E as testemunhas depuseram as suas vestes aos pés de um mancebo chamado Saulo.");
    b->dados[ATOS].capitulos[7].versos[59] = wxT("Apedrejavam, pois, a Estêvão que orando, dizia: Senhor Jesus, recebe o meu espírito.");
    b->dados[ATOS].capitulos[7].versos[60] = wxT("E pondo-se de joelhos, clamou com grande voz: Senhor, não lhes imputes este pecado. Tendo dito isto, adormeceu. E Saulo consentia na sua morte.");

    b->dados[ATOS].capitulos[8].versos[1] = wxT("Naquele dia levantou-se grande perseguição contra a igreja que estava em Jerusalém; e todos exceto os apóstolos, foram dispersos pelas regiões da Judéia e da Samária.");
    b->dados[ATOS].capitulos[8].versos[2] = wxT("E uns homens piedosos sepultaram a Estêvão, e fizeram grande pranto sobre ele.");
    b->dados[ATOS].capitulos[8].versos[3] = wxT("Saulo porém, assolava a igreja, entrando pelas casas e, arrastando homens e mulheres, os entregava à prisão.");
    b->dados[ATOS].capitulos[8].versos[4] = wxT("No entanto os que foram dispersos iam por toda parte, anunciando a palavra.");
    b->dados[ATOS].capitulos[8].versos[5] = wxT("E descendo Filipe à cidade de Samária, pregava-lhes a Cristo.");
    b->dados[ATOS].capitulos[8].versos[6] = wxT("As multidões escutavam, unânimes, as coisas que Filipe dizia, ouvindo-o e vendo os sinais que operava;");
    b->dados[ATOS].capitulos[8].versos[7] = wxT("pois saíam de muitos possessos os espíritos imundos, clamando em alta voz; e muitos paralíticos e coxos foram curados;");
    b->dados[ATOS].capitulos[8].versos[8] = wxT("pelo que houve grande alegria naquela cidade.");
    b->dados[ATOS].capitulos[8].versos[9] = wxT("Ora, estava ali certo homem chamado Simão, que vinha exercendo naquela cidade a arte mágica, fazendo pasmar o povo da Samária, e dizendo ser ele uma grande personagem;");
    b->dados[ATOS].capitulos[8].versos[10] = wxT("ao qual todos atendiam, desde o menor até o maior, dizendo: Este é o Poder de Deus que se chama Grande.");
    b->dados[ATOS].capitulos[8].versos[11] = wxT("Eles o atendiam porque já desde muito tempo os vinha fazendo pasmar com suas artes mágicas.");
    b->dados[ATOS].capitulos[8].versos[12] = wxT("Mas, quando creram em Filipe, que lhes pregava acerca do reino de Deus e do nome de Jesus, batizavam-se homens e mulheres.");
    b->dados[ATOS].capitulos[8].versos[13] = wxT("E creu até o próprio Simão e, sendo batizado, ficou de contínuo com Filipe; e admirava-se, vendo os sinais e os grandes milagres que se faziam.");
    b->dados[ATOS].capitulos[8].versos[14] = wxT("Os apóstolos, pois, que estavam em Jerusalém, tendo ouvido que os da Samária haviam recebido a palavra de Deus, enviaram-lhes Pedro e João;");
    b->dados[ATOS].capitulos[8].versos[15] = wxT("os quais, tendo descido, oraram por eles, para que recebessem o Espírito Santo.");
    b->dados[ATOS].capitulos[8].versos[16] = wxT("Porque sobre nenhum deles havia ele descido ainda; mas somente tinham sido batizados em nome do Senhor Jesus.");
    b->dados[ATOS].capitulos[8].versos[17] = wxT("Então lhes impuseram as mãos, e eles receberam o Espírito Santo.");
    b->dados[ATOS].capitulos[8].versos[18] = wxT("Quando Simão viu que pela imposição das mãos dos apóstolos se dava o Espírito Santo, ofereceu-lhes dinheiro,");
    b->dados[ATOS].capitulos[8].versos[19] = wxT("dizendo: Dai-me também a mim esse poder, para que aquele sobre quem eu impuser as mãos, receba o Espírito Santo.");
    b->dados[ATOS].capitulos[8].versos[20] = wxT("Mas disse-lhe Pedro: Vá tua prata contigo à perdição, pois cuidaste adquirir com dinheiro o dom de Deus.");
    b->dados[ATOS].capitulos[8].versos[21] = wxT("Tu não tens parte nem sorte neste ministério, porque o teu coração não é reto diante de Deus.");
    b->dados[ATOS].capitulos[8].versos[22] = wxT("Arrepende-te, pois, dessa tua maldade, e roga ao Senhor para que porventura te seja perdoado o pensamento do teu coração;");
    b->dados[ATOS].capitulos[8].versos[23] = wxT("pois vejo que estás em fel de amargura, e em laços de iniqüidade.");
    b->dados[ATOS].capitulos[8].versos[24] = wxT("Respondendo, porém, Simão, disse: Rogai vós por mim ao Senhor, para que nada do que haveis dito venha sobre mim.");
    b->dados[ATOS].capitulos[8].versos[25] = wxT("Eles, pois, havendo testificado e falado a palavra do Senhor, voltando para Jerusalém, evangelizavam muitas aldeias dos samaritanos.");
    b->dados[ATOS].capitulos[8].versos[26] = wxT("Mas um anjo do Senhor falou a Filipe, dizendo: Levanta-te, e vai em direção do sul pelo caminho que desce de Jerusalém a Gaza, o qual está deserto.");
    b->dados[ATOS].capitulos[8].versos[27] = wxT("E levantou-se e foi; e eis que um etíope, eunuco, mordomo-mor de Candace, rainha dos etíopes, o qual era superintendente de todos os seus tesouros e tinha ido a Jerusalém para adorar,");
    b->dados[ATOS].capitulos[8].versos[28] = wxT("regressava e, sentado no seu carro, lia o profeta Isaías.");
    b->dados[ATOS].capitulos[8].versos[29] = wxT("Disse o Espírito a Filipe: Chega-te e ajunta-te a esse carro.");
    b->dados[ATOS].capitulos[8].versos[30] = wxT("E correndo Filipe, ouviu que lia o profeta Isaías, e disse: Entendes, porventura, o que estás lendo?");
    b->dados[ATOS].capitulos[8].versos[31] = wxT("Ele respondeu: Pois como poderei entender, se alguém não me ensinar? e rogou a Filipe que subisse e com ele se sentasse.");
    b->dados[ATOS].capitulos[8].versos[32] = wxT("Ora, a passagem da Escritura que estava lendo era esta: Foi levado como a ovelha ao matadouro, e, como está mudo o cordeiro diante do que o tosquia, assim ele não abre a sua boca.");
    b->dados[ATOS].capitulos[8].versos[33] = wxT("Na sua humilhação foi tirado o seu julgamento; quem contará a sua geração? porque a sua vida é tirada da terra.");
    b->dados[ATOS].capitulos[8].versos[34] = wxT("Respondendo o eunuco a Filipe, disse: Rogo-te, de quem diz isto o profeta? de si mesmo, ou de algum outro?");
    b->dados[ATOS].capitulos[8].versos[35] = wxT("Então Filipe tomou a palavra e, começando por esta escritura, anunciou-lhe a Jesus.");
    b->dados[ATOS].capitulos[8].versos[36] = wxT("E indo eles caminhando, chegaram a um lugar onde havia água, e disse o eunuco: Eis aqui água; que impede que eu seja batizado?");
    b->dados[ATOS].capitulos[8].versos[37] = wxT("{E disse Felipe: é lícito, se crês de todo o coração. E, respondendo ele, disse: Creio que Jesus Cristo é o Filho de Deus.}");
    b->dados[ATOS].capitulos[8].versos[38] = wxT("mandou parar o carro, e desceram ambos à água, tanto Filipe como o eunuco, e Filipe o batizou.");
    b->dados[ATOS].capitulos[8].versos[39] = wxT("Quando saíram da água, o Espírito do Senhor arrebatou a Filipe, e não o viu mais o eunuco, que jubiloso seguia o seu caminho.");
    b->dados[ATOS].capitulos[8].versos[40] = wxT("Mas Filipe achou-se em Azoto e, indo passando, evangelizava todas as cidades, até que chegou a Cesaréia.");

    b->dados[ATOS].capitulos[9].versos[1] = wxT("Saulo, porém, respirando ainda ameaças e mortes contra os discípulos do Senhor, dirigiu-se ao sumo sacerdote,");
    b->dados[ATOS].capitulos[9].versos[2] = wxT("e pediu-lhe cartas para Damasco, para as sinagogas, a fim de que, caso encontrasse alguns do Caminho, quer homens quer mulheres, os conduzisse presos a Jerusalém.");
    b->dados[ATOS].capitulos[9].versos[3] = wxT("Mas, seguindo ele viagem e aproximando-se de Damasco, subitamente o cercou um resplendor de luz do céu;");
    b->dados[ATOS].capitulos[9].versos[4] = wxT("e, caindo por terra, ouviu uma voz que lhe dizia: Saulo, Saulo, por que me persegues?");
    b->dados[ATOS].capitulos[9].versos[5] = wxT("Ele perguntou: Quem és tu, Senhor? Respondeu o Senhor: Eu sou Jesus, a quem tu persegues;");
    b->dados[ATOS].capitulos[9].versos[6] = wxT("mas levanta-te e entra na cidade, e lá te será dito o que te cumpre fazer.");
    b->dados[ATOS].capitulos[9].versos[7] = wxT("Os homens que viajavam com ele quedaram-se emudecidos, ouvindo, na verdade, a voz, mas não vendo ninguém.");
    b->dados[ATOS].capitulos[9].versos[8] = wxT("Saulo levantou-se da terra e, abrindo os olhos, não via coisa alguma; e, guiando-o pela mão, conduziram-no a Damasco.");
    b->dados[ATOS].capitulos[9].versos[9] = wxT("E esteve três dias sem ver, e não comeu nem bebeu.");
    b->dados[ATOS].capitulos[9].versos[10] = wxT("Ora, havia em Damasco certo discípulo chamado Ananias; e disse-lhe o Senhor em visão: Ananias! Respondeu ele: Eis-me aqui, Senhor.");
    b->dados[ATOS].capitulos[9].versos[11] = wxT("Ordenou-lhe o Senhor: Levanta-te, vai à rua chamada Direita e procura em casa de Judas um homem de Tarso chamado Saulo; pois eis que ele está orando;");
    b->dados[ATOS].capitulos[9].versos[12] = wxT("e viu um homem chamado Ananias entrar e impor-lhe as mãos, para que recuperasse a vista.");
    b->dados[ATOS].capitulos[9].versos[13] = wxT("Respondeu Ananias: Senhor, a muitos ouvi acerca desse homem, quantos males tem feito aos teus santos em Jerusalém;");
    b->dados[ATOS].capitulos[9].versos[14] = wxT("e aqui tem poder dos principais sacerdotes para prender a todos os que invocam o teu nome.");
    b->dados[ATOS].capitulos[9].versos[15] = wxT("Disse-lhe, porém, o Senhor: Vai, porque este é para mim um vaso escolhido, para levar o meu nome perante os gentios, e os reis, e os filhos de Israel;");
    b->dados[ATOS].capitulos[9].versos[16] = wxT("pois eu lhe mostrarei quanto lhe cumpre padecer pelo meu nome.");
    b->dados[ATOS].capitulos[9].versos[17] = wxT("Partiu Ananias e entrou na casa e, impondo-lhe as mãos, disse: Irmão Saulo, o Senhor Jesus, que te apareceu no caminho por onde vinhas, enviou-me para que tornes a ver e sejas cheio do Espírito Santo.");
    b->dados[ATOS].capitulos[9].versos[18] = wxT("Logo lhe caíram dos olhos como que umas escamas, e recuperou a vista: então, levantando-se, foi batizado.");
    b->dados[ATOS].capitulos[9].versos[19] = wxT("E, tendo tomado alimento, ficou fortalecido. Depois demorou-se alguns dias com os discípulos que estavam em Damasco;");
    b->dados[ATOS].capitulos[9].versos[20] = wxT("e logo nas sinagogas pregava a Jesus, que este era o filho de Deus.");
    b->dados[ATOS].capitulos[9].versos[21] = wxT("Todos os seus ouvintes pasmavam e diziam: Não é este o que em Jerusalém perseguia os que invocavam esse nome, e para isso veio aqui, para os levar presos aos principais sacerdotes?");
    b->dados[ATOS].capitulos[9].versos[22] = wxT("Saulo, porém, se fortalecia cada vez mais e confundia os judeus que habitavam em Damasco, provando que Jesus era o Cristo.");
    b->dados[ATOS].capitulos[9].versos[23] = wxT("Decorridos muitos dias, os judeus deliberaram entre si matá-lo.");
    b->dados[ATOS].capitulos[9].versos[24] = wxT("Mas as suas ciladas vieram ao conhecimento de Saulo. E como eles guardavam as portas de dia e de noite para tirar-lhe a vida,");
    b->dados[ATOS].capitulos[9].versos[25] = wxT("os discípulos, tomando-o de noite, desceram-no pelo muro, dentro de um cesto.");
    b->dados[ATOS].capitulos[9].versos[26] = wxT("Tendo Saulo chegado a Jerusalém, procurava juntar-se aos discípulos; mas todos o temiam, não crendo que fosse discípulo.");
    b->dados[ATOS].capitulos[9].versos[27] = wxT("Então Barnabé, tomando-o consigo, o levou aos apóstolos, e lhes contou como no caminho ele vira o Senhor e que este lhe falara, e como em Damasco pregara ousadamente em nome de Jesus.");
    b->dados[ATOS].capitulos[9].versos[28] = wxT("Assim andava com eles em Jerusalém, entrando e saindo,");
    b->dados[ATOS].capitulos[9].versos[29] = wxT("e pregando ousadamente em nome do Senhor. Falava e disputava também com os helenistas; mas procuravam matá-lo.");
    b->dados[ATOS].capitulos[9].versos[30] = wxT("Os irmãos, porém, quando o souberam, acompanharam-no até Cesaréia e o enviaram a Tarso.");
    b->dados[ATOS].capitulos[9].versos[31] = wxT("Assim, pois, a igreja em toda a Judéia, Galiléia e Samária, tinha paz, sendo edificada, e andando no temor do Senhor; e, pelo auxílio do Espírito Santo, se multiplicava.");
    b->dados[ATOS].capitulos[9].versos[32] = wxT("E aconteceu que, passando Pedro por toda parte, veio também aos santos que habitavam em Lida.");
    b->dados[ATOS].capitulos[9].versos[33] = wxT("Achou ali certo homem, chamado Enéias, que havia oito anos jazia numa cama, porque era paralítico.");
    b->dados[ATOS].capitulos[9].versos[34] = wxT("Disse-lhe Pedro: Enéias, Jesus Cristo te cura; levanta e faze a tua cama. E logo se levantou.");
    b->dados[ATOS].capitulos[9].versos[35] = wxT("E viram-no todos os que habitavam em Lida e Sarona, os quais se converteram ao Senhor.");
    b->dados[ATOS].capitulos[9].versos[36] = wxT("Havia em Jope uma discípula por nome Tabita, que traduzido quer dizer Dorcas, a qual estava cheia de boas obras e esmolas que fazia.");
    b->dados[ATOS].capitulos[9].versos[37] = wxT("Ora, aconteceu naqueles dias que ela, adoecendo, morreu; e, tendo-a lavado, a colocaram no cenáculo.");
    b->dados[ATOS].capitulos[9].versos[38] = wxT("Como Lida era perto de Jope, ouvindo os discípulos que Pedro estava ali, enviaram-lhe dois homens, rogando-lhe: Não te demores em vir ter conosco.");
    b->dados[ATOS].capitulos[9].versos[39] = wxT("Pedro levantou-se e foi com eles; quando chegou, levaram-no ao cenáculo; e todas as viúvas o cercaram, chorando e mostrando-lhe as túnicas e vestidos que Dorcas fizera enquanto estava com elas.");
    b->dados[ATOS].capitulos[9].versos[40] = wxT("Mas Pedro, tendo feito sair a todos, pôs-se de joelhos e orou; e voltando-se para o corpo, disse: Tabita, levanta-te. Ela abriu os olhos e, vendo a Pedro, sentou-se.");
    b->dados[ATOS].capitulos[9].versos[41] = wxT("Ele, dando-lhe a mão, levantou-a e, chamando os santos e as viúvas, apresentou-lha viva.");
    b->dados[ATOS].capitulos[9].versos[42] = wxT("Tornou-se isto notório por toda a Jope, e muitos creram no Senhor.");
    b->dados[ATOS].capitulos[9].versos[43] = wxT("Pedro ficou muitos dias em Jope, em casa de um curtidor chamado Simão.");

    b->dados[ATOS].capitulos[10].versos[1] = wxT("Um homem em Cesaréia, por nome Cornélio, centurião da corte chamada italiana,");
    b->dados[ATOS].capitulos[10].versos[2] = wxT("piedoso e temente a Deus com toda a sua casa, e que fazia muitas esmolas ao povo e de contínuo orava a Deus,");
    b->dados[ATOS].capitulos[10].versos[3] = wxT("cerca da hora nona do dia, viu claramente em visão um anjo de Deus, que se dirigia para ele e lhe dizia: Cornélio!");
    b->dados[ATOS].capitulos[10].versos[4] = wxT("Este, fitando nele os olhos e atemorizado, perguntou: Que é, Senhor? O anjo respondeu-lhe: As tuas orações e as tuas esmolas têm subido para memória diante de Deus;");
    b->dados[ATOS].capitulos[10].versos[5] = wxT("agora, pois, envia homens a Jope e manda chamar a Simão, que tem por sobrenome Pedro;");
    b->dados[ATOS].capitulos[10].versos[6] = wxT("este se acha hospedado com um certo Simão, curtidor, cuja casa fica à beira-mar. {Ele te dirá o que deves fazer.}");
    b->dados[ATOS].capitulos[10].versos[7] = wxT("Logo que se retirou o anjo que lhe falava, Cornélio chamou dois dos seus domésticos e um piedoso soldado dos que estavam a seu serviço;");
    b->dados[ATOS].capitulos[10].versos[8] = wxT("e, havendo contado tudo, os enviou a Jope.");
    b->dados[ATOS].capitulos[10].versos[9] = wxT("No dia seguinte, indo eles seu caminho e estando já perto da cidade, subiu Pedro ao eirado para orar, cerca de hora sexta.");
    b->dados[ATOS].capitulos[10].versos[10] = wxT("E tendo fome, quis comer; mas enquanto lhe preparavam a comida, sobreveio-lhe um êxtase,");
    b->dados[ATOS].capitulos[10].versos[11] = wxT("e via o céu aberto e um objeto descendo, como se fosse um grande lençol, sendo baixado pelas quatro pontas sobre a terra,");
    b->dados[ATOS].capitulos[10].versos[12] = wxT("no qual havia de todos os quadrúpedes e répteis da terra e aves do céu.");
    b->dados[ATOS].capitulos[10].versos[13] = wxT("E uma voz lhe disse: Levanta-te, Pedro, mata e come.");
    b->dados[ATOS].capitulos[10].versos[14] = wxT("Mas Pedro respondeu: De modo nenhum, Senhor, porque nunca comi coisa alguma comum e imunda.");
    b->dados[ATOS].capitulos[10].versos[15] = wxT("Pela segunda vez lhe falou a voz: Não chames tu comum ao que Deus purificou.");
    b->dados[ATOS].capitulos[10].versos[16] = wxT("Sucedeu isto por três vezes; e logo foi o objeto recolhido ao céu.");
    b->dados[ATOS].capitulos[10].versos[17] = wxT("Enquanto Pedro refletia, perplexo, sobre o que seria a visão que tivera, eis que os homens enviados por Cornélio, tendo perguntado pela casa de Simão, pararam à porta.");
    b->dados[ATOS].capitulos[10].versos[18] = wxT("E, chamando, indagavam se ali estava hospedado Simão, que tinha por sobrenome Pedro.");
    b->dados[ATOS].capitulos[10].versos[19] = wxT("Estando Pedro ainda a meditar sobre a visão, o Espírito lhe disse: Eis que dois homens te procuram.");
    b->dados[ATOS].capitulos[10].versos[20] = wxT("Levanta-te, pois, desce e vai com eles, nada duvidando; porque eu tos enviei.");
    b->dados[ATOS].capitulos[10].versos[21] = wxT("E descendo Pedro ao encontro desses homens, disse: Sou eu a quem procurais; qual é a causa por que viestes?");
    b->dados[ATOS].capitulos[10].versos[22] = wxT("Eles responderam: O centurião Cornélio, homem justo e temente a Deus e que tem bom testemunho de toda a nação judaica, foi avisado por um santo anjo para te chamar à sua casa e ouvir as tuas palavras.");
    b->dados[ATOS].capitulos[10].versos[23] = wxT("Pedro, pois, convidando-os a entrar, os hospedou. No dia seguinte levantou-se e partiu com eles, e alguns irmãos, dentre os de Jope, o acompanharam.");
    b->dados[ATOS].capitulos[10].versos[24] = wxT("No outro dia entrou em Cesaréia. E Cornélio os esperava, tendo reunido os seus parentes e amigos mais íntimos.");
    b->dados[ATOS].capitulos[10].versos[25] = wxT("Quando Pedro ia entrar, veio-lhe Cornélio ao encontro e, prostrando-se a seus pés, o adorou.");
    b->dados[ATOS].capitulos[10].versos[26] = wxT("Mas Pedro o ergueu, dizendo: Levanta-te, que eu também sou homem.");
    b->dados[ATOS].capitulos[10].versos[27] = wxT("E conversando com ele, entrou e achou muitos reunidos,");
    b->dados[ATOS].capitulos[10].versos[28] = wxT("e disse-lhes: Vós bem sabeis que não é lícito a um judeu ajuntar-se ou chegar-se a estrangeiros; mas Deus mostrou-me que a nenhum homem devo chamar comum ou imundo;");
    b->dados[ATOS].capitulos[10].versos[29] = wxT("pelo que, sendo chamado, vim sem objeção. Pergunto pois: Por que razão mandastes chamar-me?");
    b->dados[ATOS].capitulos[10].versos[30] = wxT("Então disse Cornélio: Faz agora quatro dias que eu estava orando em minha casa à hora nona, e eis que diante de mim se apresentou um homem com vestiduras resplandecentes,");
    b->dados[ATOS].capitulos[10].versos[31] = wxT("e disse: Cornélio, a tua oração foi ouvida, e as tuas esmolas estão em memória diante de Deus.");
    b->dados[ATOS].capitulos[10].versos[32] = wxT("Envia, pois, a Jope e manda chamar a Simão, que tem por sobrenome Pedro; ele está hospedado em casa de Simão, curtidor, à beira-mar.");
    b->dados[ATOS].capitulos[10].versos[33] = wxT("Portanto mandei logo chamar-te, e bem fizeste em vir. Agora pois estamos todos aqui presentes diante de Deus, para ouvir tudo quanto te foi ordenado pelo Senhor.");
    b->dados[ATOS].capitulos[10].versos[34] = wxT("Então Pedro, tomando a palavra, disse: Na verdade reconheço que Deus não faz acepção de pessoas;");
    b->dados[ATOS].capitulos[10].versos[35] = wxT("mas que lhe é aceitável aquele que, em qualquer nação, o teme e pratica o que é justo.");
    b->dados[ATOS].capitulos[10].versos[36] = wxT("A palavra que ele enviou aos filhos de Israel, anunciando a paz por Jesus Cristo {este é o Senhor de todos}.");
    b->dados[ATOS].capitulos[10].versos[37] = wxT("esta palavra, vós bem sabeis, foi proclamada por toda a Judéia, começando pela Galiléia, depois do batismo que João pregou,");
    b->dados[ATOS].capitulos[10].versos[38] = wxT("concernente a Jesus de Nazaré, como Deus o ungiu com o Espírito Santo e com poder; o qual andou por toda parte, fazendo o bem e curando a todos os oprimidos do Diabo, porque Deus era com ele.");
    b->dados[ATOS].capitulos[10].versos[39] = wxT("Nós somos testemunhas de tudo quanto fez, tanto na terra dos judeus como em Jerusalém; ao qual mataram, pendurando-o num madeiro.");
    b->dados[ATOS].capitulos[10].versos[40] = wxT("A este ressuscitou Deus ao terceiro dia e lhe concedeu que se manifestasse,");
    b->dados[ATOS].capitulos[10].versos[41] = wxT("não a todo povo, mas às testemunhas que Deus antes ordenara; a nós, que comemos e bebemos juntamente com ele depois que ressurgiu dentre os mortos.");
    b->dados[ATOS].capitulos[10].versos[42] = wxT("Este nos mandou pregar ao povo, e testificar que ele é o que por Deus foi constituído juiz dos vivos e dos mortos.");
    b->dados[ATOS].capitulos[10].versos[43] = wxT("A ele todos os profetas dão testemunho de que todo o que nele crê receberá a remissão dos pecados pelo seu nome.");
    b->dados[ATOS].capitulos[10].versos[44] = wxT("Enquanto Pedro ainda dizia estas coisas, desceu o Espírito Santo sobre todos os que ouviam a palavra.");
    b->dados[ATOS].capitulos[10].versos[45] = wxT("Os crentes que eram de circuncisão, todos quantos tinham vindo com Pedro, maravilharam-se de que também sobre os gentios se derramasse o dom do Espírito Santo;");
    b->dados[ATOS].capitulos[10].versos[46] = wxT("porque os ouviam falar línguas e magnificar a Deus.");
    b->dados[ATOS].capitulos[10].versos[47] = wxT("Respondeu então Pedro: Pode alguém porventura recusar a água para que não sejam batizados estes que também, como nós, receberam o Espírito Santo?");
    b->dados[ATOS].capitulos[10].versos[48] = wxT("Mandou, pois, que fossem batizados em nome de Jesus Cristo. Então lhe rogaram que ficasse com eles por alguns dias.");

    b->dados[ATOS].capitulos[11].versos[1] = wxT("Ora, ouviram os apóstolos e os irmãos que estavam na Judéia que também os gentios haviam recebido a palavra de Deus.");
    b->dados[ATOS].capitulos[11].versos[2] = wxT("E quando Pedro subiu a Jerusalém, disputavam com ele os que eram da circuncisão,");
    b->dados[ATOS].capitulos[11].versos[3] = wxT("dizendo: Entraste em casa de homens incircuncisos e comeste com eles.");
    b->dados[ATOS].capitulos[11].versos[4] = wxT("Pedro, porém, começou a fazer-lhes uma exposição por ordem, dizendo:");
    b->dados[ATOS].capitulos[11].versos[5] = wxT("Estava eu orando na cidade de Jope, e em êxtase tive uma visão; descia um objeto, como se fosse um grande lençol, sendo baixado do céu pelas quatro pontas, e chegou perto de mim.");
    b->dados[ATOS].capitulos[11].versos[6] = wxT("E, fitando nele os olhos, o contemplava, e vi quadrúpedes da terra, feras, répteis e aves do céu.");
    b->dados[ATOS].capitulos[11].versos[7] = wxT("Ouvi também uma voz que me dizia: Levanta-te, Pedro, mata e come.");
    b->dados[ATOS].capitulos[11].versos[8] = wxT("Mas eu respondi: De modo nenhum, Senhor, pois nunca em minha boca entrou coisa alguma comum e imunda.");
    b->dados[ATOS].capitulos[11].versos[9] = wxT("Mas a voz respondeu-me do céu segunda vez: Não chames tu comum ao que Deus purificou.");
    b->dados[ATOS].capitulos[11].versos[10] = wxT("Sucedeu isto por três vezes; e tudo tornou a recolher-se ao céu.");
    b->dados[ATOS].capitulos[11].versos[11] = wxT("E eis que, nesse momento, pararam em frente à casa onde estávamos três homens que me foram enviados de Cesaréia.");
    b->dados[ATOS].capitulos[11].versos[12] = wxT("Disse-me o Espírito que eu fosse com eles, sem hesitar; e também estes seis irmãos foram comigo e entramos na casa daquele homem.");
    b->dados[ATOS].capitulos[11].versos[13] = wxT("E ele nos contou como vira em pé em sua casa o anjo, que lhe dissera: Envia a Jope e manda chamar a Simão, que tem por sobrenome Pedro,");
    b->dados[ATOS].capitulos[11].versos[14] = wxT("o qual te dirá palavras pelas quais serás salvo, tu e toda a tua casa.");
    b->dados[ATOS].capitulos[11].versos[15] = wxT("Logo que eu comecei a falar, desceu sobre eles o Espírito Santo, como também sobre nós no princípio.");
    b->dados[ATOS].capitulos[11].versos[16] = wxT("Lembrei-me então da palavra do Senhor, como disse: João, na verdade, batizou com água; mas vós sereis batizados no Espírito Santo.");
    b->dados[ATOS].capitulos[11].versos[17] = wxT("Portanto, se Deus lhes deu o mesmo dom que dera também a nós, ao crermos no Senhor Jesus Cristo, quem era eu, para que pudesse resistir a Deus?");
    b->dados[ATOS].capitulos[11].versos[18] = wxT("Ouvindo eles estas coisas, apaziguaram-se e glorificaram a Deus, dizendo: Assim, pois, Deus concedeu também aos gentios o arrependimento para a vida.");
    b->dados[ATOS].capitulos[11].versos[19] = wxT("Aqueles, pois, que foram dispersos pela tribulação suscitada por causa de Estêvão, passaram até a Fenícia, Chipre e Antioquia, não anunciando a ninguém a palavra, senão somente aos judeus.");
    b->dados[ATOS].capitulos[11].versos[20] = wxT("Havia, porém, entre eles alguns cíprios e cirenenses, os quais, entrando em Antioquia, falaram também aos gregos, anunciando o Senhor Jesus.");
    b->dados[ATOS].capitulos[11].versos[21] = wxT("E a mão do Senhor era com eles, e grande número creu e se converteu ao Senhor.");
    b->dados[ATOS].capitulos[11].versos[22] = wxT("Chegou a notícia destas coisas aos ouvidos da igreja em Jerusalém; e enviaram Barnabé a Antioquia;");
    b->dados[ATOS].capitulos[11].versos[23] = wxT("o qual, quando chegou e viu a graça de Deus, se alegrou, e exortava a todos a perseverarem no Senhor com firmeza de coração;");
    b->dados[ATOS].capitulos[11].versos[24] = wxT("porque era homem de bem, e cheio do Espírito Santo e de fé. E muita gente se uniu ao Senhor.");
    b->dados[ATOS].capitulos[11].versos[25] = wxT("Partiu, pois, Barnabé para Tarso, em busca de Saulo;");
    b->dados[ATOS].capitulos[11].versos[26] = wxT("e tendo-o achado, o levou para Antioquia. E durante um ano inteiro reuniram-se naquela igreja e instruíram muita gente; e em Antioquia os discípulos pela primeira vez foram chamados cristãos.");
    b->dados[ATOS].capitulos[11].versos[27] = wxT("Naqueles dias desceram profetas de Jerusalém para Antioquia;");
    b->dados[ATOS].capitulos[11].versos[28] = wxT("e levantando-se um deles, de nome Ágabo, dava a entender pelo Espírito, que haveria uma grande fome por todo o mundo, a qual ocorreu no tempo de Cláudio.");
    b->dados[ATOS].capitulos[11].versos[29] = wxT("E os discípulos resolveram mandar, cada um conforme suas posses, socorro aos irmãos que habitavam na Judéia;");
    b->dados[ATOS].capitulos[11].versos[30] = wxT("o que eles com efeito fizeram, enviando-o aos anciãos por mão de Barnabé e Saulo.");

    b->dados[ATOS].capitulos[12].versos[1] = wxT("Por aquele mesmo tempo o rei Herodes estendeu as mãos sobre alguns da igreja, para os maltratar;");
    b->dados[ATOS].capitulos[12].versos[2] = wxT("e matou à espada Tiago, irmão de João.");
    b->dados[ATOS].capitulos[12].versos[3] = wxT("Vendo que isso agradava aos judeus, continuou, mandando prender também a Pedro. {Eram então os dias dos pães ázimos.}");
    b->dados[ATOS].capitulos[12].versos[4] = wxT("E, havendo-o prendido, lançou-o na prisão, entregando-o a quatro grupos de quatro soldados cada um para o guardarem, tencionando apresentá-lo ao povo depois da páscoa.");
    b->dados[ATOS].capitulos[12].versos[5] = wxT("Pedro, pois, estava guardado na prisão; mas a igreja orava com insistência a Deus por ele.");
    b->dados[ATOS].capitulos[12].versos[6] = wxT("Ora quando Herodes estava para apresentá-lo, nessa mesma noite estava Pedro dormindo entre dois soldados, acorrentado com duas cadeias e as sentinelas diante da porta guardavam a prisão.");
    b->dados[ATOS].capitulos[12].versos[7] = wxT("E eis que sobreveio um anjo do Senhor, e uma luz resplandeceu na prisão; e ele, tocando no lado de Pedro, o despertou, dizendo: Levanta-te depressa. E caíram-lhe das mãos as cadeias.");
    b->dados[ATOS].capitulos[12].versos[8] = wxT("Disse-lhe ainda o anjo: Cinge-te e calça as tuas sandálias. E ele o fez. Disse-lhe mais; Cobre-te com a tua capa e segue-me.");
    b->dados[ATOS].capitulos[12].versos[9] = wxT("Pedro, saindo, o seguia, mesmo sem compreender que era real o que se fazia por intermédio de um anjo, julgando que era uma visão.");
    b->dados[ATOS].capitulos[12].versos[10] = wxT("Depois de terem passado a primeira e a segunda sentinela, chegaram à porta de ferro, que dá para a cidade, a qual se lhes abriu por si mesma; e tendo saído, passaram uma rua, e logo o anjo se apartou dele.");
    b->dados[ATOS].capitulos[12].versos[11] = wxT("Pedro então, tornando a si, disse: Agora sei verdadeiramente que o Senhor enviou o seu anjo, e me livrou da mão de Herodes e de toda a expectativa do povo dos judeus.");
    b->dados[ATOS].capitulos[12].versos[12] = wxT("Depois de assim refletir foi à casa de Maria, mãe de João, que tem por sobrenome Marcos, onde muitas pessoas estavam reunidas e oravam.");
    b->dados[ATOS].capitulos[12].versos[13] = wxT("Quando ele bateu ao portão do pátio, uma criada chamada Rode saiu a escutar;");
    b->dados[ATOS].capitulos[12].versos[14] = wxT("e, reconhecendo a voz de Pedro, de gozo não abriu o portão, mas, correndo para dentro, anunciou que Pedro estava lá fora.");
    b->dados[ATOS].capitulos[12].versos[15] = wxT("Eles lhe disseram: Estás louca. Ela, porém, assegurava que assim era. Eles então diziam: É o seu anjo.");
    b->dados[ATOS].capitulos[12].versos[16] = wxT("Mas Pedro continuava a bater, e, quando abriram, viram-no e pasmaram.");
    b->dados[ATOS].capitulos[12].versos[17] = wxT("Mas ele, acenando-lhes com a mão para que se calassem, contou-lhes como o Senhor o tirara da prisão, e disse: Anunciai isto a Tiago e aos irmãos. E, saindo, partiu para outro lugar.");
    b->dados[ATOS].capitulos[12].versos[18] = wxT("Logo que amanheceu, houve grande alvoroço entre os soldados sobre o que teria sido feito de Pedro.");
    b->dados[ATOS].capitulos[12].versos[19] = wxT("E Herodes, tendo-o procurado e não o achando, inquiriu as sentinelas e mandou que fossem justiçadas; e descendo da Judéia para Cesaréia, demorou-se ali.");
    b->dados[ATOS].capitulos[12].versos[20] = wxT("Ora, Herodes estava muito irritado contra os de Tiro e de Sidom; mas estes, vindo de comum acordo ter com ele e obtendo a amizade de Blasto, camareiro do rei, pediam paz, porquanto o seu país se abastecia do país do rei.");
    b->dados[ATOS].capitulos[12].versos[21] = wxT("Num dia designado, Herodes, vestido de trajes reais, sentou-se no trono e dirigia-lhes a palavra.");
    b->dados[ATOS].capitulos[12].versos[22] = wxT("E o povo exclamava: É a voz de um deus, e não de um homem.");
    b->dados[ATOS].capitulos[12].versos[23] = wxT("No mesmo instante o anjo do Senhor o feriu, porque não deu glória a Deus; e, comido de vermes, expirou.");
    b->dados[ATOS].capitulos[12].versos[24] = wxT("E a palavra de Deus crescia e se multiplicava.");
    b->dados[ATOS].capitulos[12].versos[25] = wxT("Barnabé e Saulo, havendo terminado aquele serviço, voltaram de Jerusalém, levando consigo a João, que tem por sobrenome Marcos.");

    b->dados[ATOS].capitulos[13].versos[1] = wxT("Ora, na igreja em Antioquia havia profetas e mestres, a saber: Barnabé, Simeão, chamado Níger, Lúcio de Cirene, Manaém, colaço de Herodes o tetrarca, e Saulo.");
    b->dados[ATOS].capitulos[13].versos[2] = wxT("Enquanto eles ministravam perante o Senhor e jejuavam, disse o Espírito Santo: Separai-me a Barnabé e a Saulo para a obra a que os tenho chamado.");
    b->dados[ATOS].capitulos[13].versos[3] = wxT("Então, depois que jejuaram, oraram e lhes impuseram as mãos, os despediram.");
    b->dados[ATOS].capitulos[13].versos[4] = wxT("Estes, pois, enviados pelo Espírito Santo, desceram a Selêucia e dali navegaram para Chipre.");
    b->dados[ATOS].capitulos[13].versos[5] = wxT("Chegados a Salamina, anunciavam a palavra de Deus nas sinagogas dos judeus, e tinham a João como auxiliar.");
    b->dados[ATOS].capitulos[13].versos[6] = wxT("Havendo atravessado a ilha toda até Pafos, acharam um certo mago, falso profeta, judeu, chamado Bar-Jesus,");
    b->dados[ATOS].capitulos[13].versos[7] = wxT("que estava com o procônsul Sérgio Paulo, homem sensato. Este chamou a Barnabé e Saulo e mostrou desejo de ouvir a palavra de Deus.");
    b->dados[ATOS].capitulos[13].versos[8] = wxT("Mas resistia-lhes Elimas, o encantador {porque assim se interpreta o seu nome}, procurando desviar a fé do procônsul.");
    b->dados[ATOS].capitulos[13].versos[9] = wxT("Todavia Saulo, também chamado Paulo, cheio do Espírito Santo, fitando os olhos nele,");
    b->dados[ATOS].capitulos[13].versos[10] = wxT("disse: ó filho do diabo, cheio de todo o engano e de toda a malícia, inimigo de toda a justiça, não cessarás de perverter os caminhos retos do Senhor?");
    b->dados[ATOS].capitulos[13].versos[11] = wxT("Agora eis a mão do Senhor sobre ti, e ficarás cego, sem ver o sol por algum tempo. Imediatamente caiu sobre ele uma névoa e trevas e, andando à roda, procurava quem o guiasse pela mão.");
    b->dados[ATOS].capitulos[13].versos[12] = wxT("Então o procônsul, vendo o que havia acontecido, creu, maravilhando-se da doutrina do Senhor.");
    b->dados[ATOS].capitulos[13].versos[13] = wxT("Tendo Paulo e seus companheiros navegado de Pafos, chegaram a Perge, na Panfília. João, porém, apartando-se deles, voltou para Jerusalém.");
    b->dados[ATOS].capitulos[13].versos[14] = wxT("Mas eles, passando de Perge, chegaram a Antioquia da Psídia; e entrando na sinagoga, no dia de sábado, sentaram-se.");
    b->dados[ATOS].capitulos[13].versos[15] = wxT("Depois da leitura da lei e dos profetas, os chefes da sinagoga mandaram dizer-lhes: Irmãos, se tendes alguma palavra de exortação ao povo, falai.");
    b->dados[ATOS].capitulos[13].versos[16] = wxT("Então Paulo se levantou e, pedindo silêncio com a mão, disse: Varões israelitas, e os que temeis a Deus, ouvi:");
    b->dados[ATOS].capitulos[13].versos[17] = wxT("O Deus deste povo de Israel escolheu a nossos pais, e exaltou o povo, sendo eles estrangeiros na terra do Egito, de onde os tirou com braço poderoso,");
    b->dados[ATOS].capitulos[13].versos[18] = wxT("e suportou-lhes os maus costumes no deserto por espaço de quase quarenta anos;");
    b->dados[ATOS].capitulos[13].versos[19] = wxT("e, havendo destruído as sete nações na terra de Canaã, deu-lhes o território delas por herança durante cerca de quatrocentos e cinquenta anos.");
    b->dados[ATOS].capitulos[13].versos[20] = wxT("Depois disto, deu-lhes juízes até o profeta Samuel.");
    b->dados[ATOS].capitulos[13].versos[21] = wxT("Então pediram um rei, e Deus lhes deu por quarenta anos a Saul, filho de Cis, varão da tribo de Benjamim.");
    b->dados[ATOS].capitulos[13].versos[22] = wxT("E tendo deposto a este, levantou-lhes como rei a Davi, ao qual também, dando testemunho, disse: Achei a Davi, filho de Jessé, homem segundo o meu coração, que fará toda a minha vontade.");
    b->dados[ATOS].capitulos[13].versos[23] = wxT("Da descendência deste, conforme a promessa, trouxe Deus a Israel um Salvador, Jesus;");
    b->dados[ATOS].capitulos[13].versos[24] = wxT("havendo João, antes do aparecimento dele, pregado a todo o povo de Israel o batismo de arrependimento.");
    b->dados[ATOS].capitulos[13].versos[25] = wxT("Mas João, quando completava a carreira, dizia: Quem pensais vós que eu sou? Eu não sou o Cristo, mas eis que após mim vem aquele a quem não sou digno de desatar as alparcas dos pés.");
    b->dados[ATOS].capitulos[13].versos[26] = wxT("Irmãos, filhos da estirpe de Abraão, e os que dentre vós temem a Deus, a nós é enviada a palavra desta salvação.");
    b->dados[ATOS].capitulos[13].versos[27] = wxT("Pois, os que habitam em Jerusalém e as suas autoridades, porquanto não conheceram a este Jesus, condenando-o, cumpriram as mesmas palavras dos profetas que se ouvem ler todos os sábados.");
    b->dados[ATOS].capitulos[13].versos[28] = wxT("E, se bem que não achassem nele nenhuma causa de morte, pediram a Pilatos que ele fosse morto.");
    b->dados[ATOS].capitulos[13].versos[29] = wxT("Quando haviam cumprido todas as coisas que dele estavam escritas, tirando-o do madeiro, o puseram na sepultura;");
    b->dados[ATOS].capitulos[13].versos[30] = wxT("mas Deus o ressuscitou dentre os mortos;");
    b->dados[ATOS].capitulos[13].versos[31] = wxT("e ele foi visto durante muitos dias por aqueles que com ele subiram da Galiléia a Jerusalém, os quais agora são suas testemunhas para com o povo.");
    b->dados[ATOS].capitulos[13].versos[32] = wxT("E nós vos anunciamos as boas novas da promessa, feita aos pais,");
    b->dados[ATOS].capitulos[13].versos[33] = wxT("a qual Deus nos tem cumprido, a nós, filhos deles, levantando a Jesus, como também está escrito no salmo segundo: Tu és meu Filho, hoje te gerei.");
    b->dados[ATOS].capitulos[13].versos[34] = wxT("E no tocante a que o ressuscitou dentre os mortos para nunca mais tornar à corrupção, falou Deus assim: Dar-vos-ei as santas e fiéis bênçãos de Davi;");
    b->dados[ATOS].capitulos[13].versos[35] = wxT("pelo que ainda em outro salmo diz: Não permitirás que o teu Santo veja a corrupção.");
    b->dados[ATOS].capitulos[13].versos[36] = wxT("Porque Davi, na verdade, havendo servido a sua própria geração pela vontade de Deus, dormiu e foi depositado junto a seus pais e experimentou corrupção.");
    b->dados[ATOS].capitulos[13].versos[37] = wxT("Mas aquele a quem Deus ressuscitou nenhuma corrupção experimentou.");
    b->dados[ATOS].capitulos[13].versos[38] = wxT("Seja-vos pois notório, varões, que por este se vos anuncia a remissão dos pecados.");
    b->dados[ATOS].capitulos[13].versos[39] = wxT("E de todas as coisas de que não pudestes ser justificados pela lei de Moisés, por ele é justificado todo o que crê.");
    b->dados[ATOS].capitulos[13].versos[40] = wxT("Cuidai pois que não venha sobre vós o que está dito nos profetas:");
    b->dados[ATOS].capitulos[13].versos[41] = wxT("Vede, ó desprezadores, admirai-vos e desaparecei; porque realizo uma obra em vossos dias, obra em que de modo algum crereis, se alguém vo-la contar.");
    b->dados[ATOS].capitulos[13].versos[42] = wxT("Quando iam saindo, rogavam que estas palavras lhes fossem repetidas no sábado seguinte.");
    b->dados[ATOS].capitulos[13].versos[43] = wxT("E, despedida a sinagoga, muitos judeus e prosélitos devotos seguiram a Paulo e Barnabé, os quais, falando-lhes, os exortavam a perseverarem na graça de Deus.");
    b->dados[ATOS].capitulos[13].versos[44] = wxT("No sábado seguinte reuniu-se quase toda a cidade para ouvir a palavra de Deus.");
    b->dados[ATOS].capitulos[13].versos[45] = wxT("Mas os judeus, vendo as multidões, encheram-se de inveja e, blasfemando, contradiziam o que Paulo falava.");
    b->dados[ATOS].capitulos[13].versos[46] = wxT("Então Paulo e Barnabé, falando ousadamente, disseram: Era mister que a vós se pregasse em primeiro lugar a palavra de Deus; mas, visto que a rejeitais, e não vos julgais dignos da vida eterna, eis que nos viramos para os gentios;");
    b->dados[ATOS].capitulos[13].versos[47] = wxT("porque assim nos ordenou o Senhor: Eu te pus para luz dos gentios, a fim de que sejas para salvação até os confins da terra.");
    b->dados[ATOS].capitulos[13].versos[48] = wxT("Os gentios, ouvindo isto, alegravam-se e glorificavam a palavra do Senhor; e creram todos quantos haviam sido destinados para a vida eterna.");
    b->dados[ATOS].capitulos[13].versos[49] = wxT("E divulgava-se a palavra do Senhor por toda aquela região.");
    b->dados[ATOS].capitulos[13].versos[50] = wxT("Mas os judeus incitaram as mulheres devotas de alta posição e os principais da cidade, suscitaram uma perseguição contra Paulo e Barnabé, e os lançaram fora dos seus termos.");
    b->dados[ATOS].capitulos[13].versos[51] = wxT("Mas estes, sacudindo contra eles o pó dos seus pés, partiram para Icônio.");
    b->dados[ATOS].capitulos[13].versos[52] = wxT("Os discípulos, porém, estavam cheios de alegria e do Espírito Santo.");

    b->dados[ATOS].capitulos[14].versos[1] = wxT("Em Icônio entraram juntos na sinagoga dos judeus e falaram de tal modo que creu uma grande multidão tanto de judeus como de gregos.");
    b->dados[ATOS].capitulos[14].versos[2] = wxT("Mas os judeus incrédulos excitaram e irritaram os ânimos dos gentios contra os irmãos.");
    b->dados[ATOS].capitulos[14].versos[3] = wxT("Eles, entretanto, se demoraram ali por muito tempo, falando ousadamente acerca do Senhor, o qual dava testemunho à palavra da sua graça, concedendo que por suas mãos se fizessem sinais e prodígios.");
    b->dados[ATOS].capitulos[14].versos[4] = wxT("E se dividiu o povo da cidade; uns eram pelos judeus, e outros pelos apóstolos.");
    b->dados[ATOS].capitulos[14].versos[5] = wxT("E, havendo um motim tanto dos gentios como dos judeus, juntamente com as suas autoridades, para os ultrajarem e apedrejarem,");
    b->dados[ATOS].capitulos[14].versos[6] = wxT("eles, sabendo-o, fugiram para Listra e Derbe, cidades da Licaônia, e a região circunvizinha;");
    b->dados[ATOS].capitulos[14].versos[7] = wxT("e ali pregavam o evangelho.");
    b->dados[ATOS].capitulos[14].versos[8] = wxT("Em Listra estava sentado um homem aleijado dos pés, coxo de nascença e que nunca tinha andado.");
    b->dados[ATOS].capitulos[14].versos[9] = wxT("Este ouvia falar Paulo, que, fitando nele os olhos e vendo que tinha fé para ser curado,");
    b->dados[ATOS].capitulos[14].versos[10] = wxT("disse em alta voz: Levanta-te direito sobre os teus pés. E ele saltou, e andava.");
    b->dados[ATOS].capitulos[14].versos[11] = wxT("As multidões, vendo o que Paulo fizera, levantaram a voz, dizendo em língua licaônica: Fizeram-se os deuses semelhantes aos homens e desceram até nós.");
    b->dados[ATOS].capitulos[14].versos[12] = wxT("A Barnabé chamavam Júpiter e a Paulo, Mercúrio, porque era ele o que dirigia a palavra.");
    b->dados[ATOS].capitulos[14].versos[13] = wxT("O sacerdote de Júpiter, cujo templo estava em frente da cidade, trouxe para as portas touros e grinaldas e, juntamente com as multidões, queria oferecer-lhes sacrifícios.");
    b->dados[ATOS].capitulos[14].versos[14] = wxT("Quando, porém, os apóstolos Barnabé e Paulo ouviram isto, rasgaram as suas vestes e saltaram para o meio da multidão, clamando");
    b->dados[ATOS].capitulos[14].versos[15] = wxT("e dizendo: Senhores, por que fazeis estas coisas? Nós também somos homens, de natureza semelhante à vossa, e vos anunciamos o evangelho para que destas práticas vãs vos convertais ao Deus vivo, que fez o céu, a terra, o mar, e tudo quanto há neles;");
    b->dados[ATOS].capitulos[14].versos[16] = wxT("o qual nos tempos passados permitiu que todas as nações andassem nos seus próprios caminhos.");
    b->dados[ATOS].capitulos[14].versos[17] = wxT("Contudo não deixou de dar testemunho de si mesmo, fazendo o bem, dando-vos chuvas do céu e estações frutíferas, enchendo-vos de mantimento, e de alegria os vossos corações.");
    b->dados[ATOS].capitulos[14].versos[18] = wxT("E dizendo isto, com dificuldade impediram as multidões de lhes oferecerem sacrifícios.");
    b->dados[ATOS].capitulos[14].versos[19] = wxT("Sobrevieram, porém, judeus de Antioquia e de Icônio e, havendo persuadido as multidões, apedrejaram a Paulo, e arrastaram-no para fora da cidade, cuidando que estava morto.");
    b->dados[ATOS].capitulos[14].versos[20] = wxT("Mas quando os discípulos o rodearam, ele se levantou e entrou na cidade. No dia seguinte partiu com Barnabé para Derbe.");
    b->dados[ATOS].capitulos[14].versos[21] = wxT("E, tendo anunciado o evangelho naquela cidade e feito muitos discípulos, voltaram para Listra, Icônio e Antioquia,");
    b->dados[ATOS].capitulos[14].versos[22] = wxT("confirmando as almas dos discípulos, exortando-os a perseverarem na fé, dizendo que por muitas tribulações nos é necessário entrar no reino de Deus.");
    b->dados[ATOS].capitulos[14].versos[23] = wxT("E, havendo-lhes feito eleger anciãos em cada igreja e orado com jejuns, os encomendaram ao Senhor em quem haviam crido.");
    b->dados[ATOS].capitulos[14].versos[24] = wxT("Atravessando então a Pisídia, chegaram à Panfília.");
    b->dados[ATOS].capitulos[14].versos[25] = wxT("E, tendo anunciado a palavra em Perge, desceram a Atália.");
    b->dados[ATOS].capitulos[14].versos[26] = wxT("E dali navegaram para Antioquia, donde tinham sido encomendados à graça de Deus para a obra que acabavam de cumprir.");
    b->dados[ATOS].capitulos[14].versos[27] = wxT("Quando chegaram e reuniram a igreja, relataram tudo quanto Deus fizera por meio deles, e como abrira aos gentios a porta da fé.");
    b->dados[ATOS].capitulos[14].versos[28] = wxT("E ficaram ali não pouco tempo, com os discípulos.");

    b->dados[ATOS].capitulos[15].versos[1] = wxT("Então alguns que tinham descido da Judéia ensinavam aos irmãos: Se não vos circuncidardes, segundo o rito de Moisés, não podeis ser salvos.");
    b->dados[ATOS].capitulos[15].versos[2] = wxT("Tendo Paulo e Barnabé contenda e não pequena discussão com eles, os irmãos resolveram que Paulo e Barnabé e mais alguns dentre eles subissem a Jerusalém, aos apóstolos e aos anciãos, por causa desta questão.");
    b->dados[ATOS].capitulos[15].versos[3] = wxT("Eles, pois, sendo acompanhados pela igreja por um trecho do caminho, passavam pela Fenícia e por Samária, contando a conversão dos gentios; e davam grande alegria a todos os irmãos.");
    b->dados[ATOS].capitulos[15].versos[4] = wxT("E, quando chegaram a Jerusalém, foram recebidos pela igreja e pelos apóstolos e anciãos, e relataram tudo quanto Deus fizera por meio deles.");
    b->dados[ATOS].capitulos[15].versos[5] = wxT("Mas alguns da seita dos fariseus, que tinham crido, levantaram-se dizendo que era necessário circuncidá-los e mandar-lhes observar a lei de Moisés.");
    b->dados[ATOS].capitulos[15].versos[6] = wxT("Congregaram-se pois os apóstolos e os anciãos para considerar este assunto.");
    b->dados[ATOS].capitulos[15].versos[7] = wxT("E, havendo grande discussão, levantou-se Pedro e disse-lhes: Irmãos, bem sabeis que já há muito tempo Deus me elegeu dentre vós, para que os gentios ouvissem da minha boca a palavra do evangelho e cressem.");
    b->dados[ATOS].capitulos[15].versos[8] = wxT("E Deus, que conhece os corações, testemunhou a favor deles, dando-lhes o Espírito Santo, assim como a nós;");
    b->dados[ATOS].capitulos[15].versos[9] = wxT("e não fez distinção alguma entre eles e nós, purificando os seus corações pela fé.");
    b->dados[ATOS].capitulos[15].versos[10] = wxT("Agora, pois, por que tentais a Deus, pondo sobre a cerviz dos discípulos um jugo que nem nossos pais nem nós pudemos suportar?");
    b->dados[ATOS].capitulos[15].versos[11] = wxT("Mas cremos que somos salvos pela graça do Senhor Jesus, do mesmo modo que eles também.");
    b->dados[ATOS].capitulos[15].versos[12] = wxT("Então toda a multidão se calou e escutava a Barnabé e a Paulo, que contavam quantos sinais e prodígios Deus havia feito por meio deles entre os gentios.");
    b->dados[ATOS].capitulos[15].versos[13] = wxT("Depois que se calaram, Tiago, tomando a palavra, disse: Irmãos, ouvi-me:");
    b->dados[ATOS].capitulos[15].versos[14] = wxT("Simão relatou como primeiramente Deus visitou os gentios para tomar dentre eles um povo para o seu Nome.");
    b->dados[ATOS].capitulos[15].versos[15] = wxT("E com isto concordam as palavras dos profetas; como está escrito:");
    b->dados[ATOS].capitulos[15].versos[16] = wxT("Depois disto voltarei, e reedificarei o tabernáculo de Davi, que está caído; reedificarei as suas ruínas, e tornarei a levantá-lo;");
    b->dados[ATOS].capitulos[15].versos[17] = wxT("para que o resto dos homens busque ao Senhor, sim, todos os gentios, sobre os quais é invocado o meu nome,");
    b->dados[ATOS].capitulos[15].versos[18] = wxT("diz o Senhor que faz estas coisas, que são conhecidas desde a antiguidade.");
    b->dados[ATOS].capitulos[15].versos[19] = wxT("Por isso, julgo que não se deve perturbar aqueles, dentre os gentios, que se convertem a Deus,");
    b->dados[ATOS].capitulos[15].versos[20] = wxT("mas escrever-lhes que se abstenham das contaminações dos ídolos, da prostituição, do que é sufocado e do sangue.");
    b->dados[ATOS].capitulos[15].versos[21] = wxT("Porque Moisés, desde tempos antigos, tem em cada cidade homens que o preguem, e cada sábado é lido nas sinagogas.");
    b->dados[ATOS].capitulos[15].versos[22] = wxT("Então pareceu bem aos apóstolos e aos anciãos com toda a igreja escolher homens dentre eles e enviá-los a Antioquia com Paulo e Barnabé, a saber: Judas, chamado Barsabás, e Silas, homens influentes entre os irmãos.");
    b->dados[ATOS].capitulos[15].versos[23] = wxT("E por intermédio deles escreveram o seguinte: Os apóstolos e os anciãos, irmãos, aos irmãos dentre os gentios em Antioquia, na Síria e na Cicília, saúde.");
    b->dados[ATOS].capitulos[15].versos[24] = wxT("Portanto ouvimos que alguns dentre nós, aos quais nada mandamos, vos têm perturbado com palavras, confundindo as vossas almas,");
    b->dados[ATOS].capitulos[15].versos[25] = wxT("pareceu-nos bem, tendo chegado a um acordo, escolher alguns homens e enviá-los com os nossos amados Barnabé e Paulo,");
    b->dados[ATOS].capitulos[15].versos[26] = wxT("homens que têm exposto as suas vidas pelo nome de nosso Senhor Jesus Cristo.");
    b->dados[ATOS].capitulos[15].versos[27] = wxT("Enviamos portanto Judas e Silas, os quais também por palavra vos anunciarão as mesmas coisas.");
    b->dados[ATOS].capitulos[15].versos[28] = wxT("Porque pareceu bem ao Espírito Santo e a nós não vos impor maior encargo além destas coisas necessárias:");
    b->dados[ATOS].capitulos[15].versos[29] = wxT("Que vos abstenhais das coisas sacrificadas aos ídolos, e do sangue, e da carne sufocada, e da prostituição; e destas coisas fareis bem de vos guardar. Bem vos vá.");
    b->dados[ATOS].capitulos[15].versos[30] = wxT("Então eles, tendo-se despedido, desceram a Antioquia e, havendo reunido a assembléia, entregaram a carta.");
    b->dados[ATOS].capitulos[15].versos[31] = wxT("E, quando a leram, alegraram-se pela consolação.");
    b->dados[ATOS].capitulos[15].versos[32] = wxT("Depois Judas e Silas, que também eram profetas, exortaram os irmãos com muitas palavras e os fortaleceram.");
    b->dados[ATOS].capitulos[15].versos[33] = wxT("E, tendo-se demorado ali por algum tempo, foram pelos irmãos despedidos em paz, de volta aos que os haviam mandado.");
    b->dados[ATOS].capitulos[15].versos[34] = wxT("{Mas pareceu bem a Silas ficar ali.}");
    b->dados[ATOS].capitulos[15].versos[35] = wxT("Mas Paulo e Barnabé demoraram-se em Antioquia, ensinando e pregando com muitos outros a palavra do Senhor.");
    b->dados[ATOS].capitulos[15].versos[36] = wxT("Decorridos alguns dias, disse Paulo a Barnabé: Tornemos a visitar os irmãos por todas as cidades em que temos anunciado a palavra do Senhor, para ver como vão.");
    b->dados[ATOS].capitulos[15].versos[37] = wxT("Ora, Barnabé queria que levassem também a João, chamado Marcos.");
    b->dados[ATOS].capitulos[15].versos[38] = wxT("Mas a Paulo não parecia razoável que tomassem consigo aquele que desde a Panfília se tinha apartado deles e não os tinha acompanhado no trabalho.");
    b->dados[ATOS].capitulos[15].versos[39] = wxT("E houve entre eles tal desavença que se separaram um do outro, e Barnabé, levando consigo a Marcos, navegou para Chipre.");
    b->dados[ATOS].capitulos[15].versos[40] = wxT("Mas Paulo, tendo escolhido a Silas, partiu encomendado pelos irmãos à graça do Senhor.");
    b->dados[ATOS].capitulos[15].versos[41] = wxT("E passou pela Síria e Cilícia, fortalecendo as igrejas.");

    b->dados[ATOS].capitulos[16].versos[1] = wxT("Chegou também a Derbe e Listra. E eis que estava ali certo discípulo por nome Timóteo, filho de uma judia crente, mas de pai grego;");
    b->dados[ATOS].capitulos[16].versos[2] = wxT("do qual davam bom testemunho os irmãos em Listra e Icônio.");
    b->dados[ATOS].capitulos[16].versos[3] = wxT("Paulo quis que este fosse com ele e, tomando-o, o circuncidou por causa dos judeus que estavam naqueles lugares; porque todos sabiam que seu pai era grego.");
    b->dados[ATOS].capitulos[16].versos[4] = wxT("Quando iam passando pelas cidades, entregavam aos irmãos, para serem observadas, as decisões que haviam sido tomadas pelos apóstolos e anciãos em Jerusalém.");
    b->dados[ATOS].capitulos[16].versos[5] = wxT("Assim as igrejas eram confirmadas na fé, e dia a dia cresciam em número.");
    b->dados[ATOS].capitulos[16].versos[6] = wxT("Atravessaram a região frígio-gálata, tendo sido impedidos pelo Espírito Santo de anunciar a palavra na Ásia;");
    b->dados[ATOS].capitulos[16].versos[7] = wxT("e tendo chegado diante da Mísia, tentavam ir para Bitínia, mas o Espírito de Jesus não lho permitiu.");
    b->dados[ATOS].capitulos[16].versos[8] = wxT("Então, passando pela Mísia, desceram a Trôade.");
    b->dados[ATOS].capitulos[16].versos[9] = wxT("De noite apareceu a Paulo esta visão: estava ali em pé um homem da Macedônia, que lhe rogava: Passa à Macedônia e ajuda-nos.");
    b->dados[ATOS].capitulos[16].versos[10] = wxT("E quando ele teve esta visão, procurávamos logo partir para a Macedônia, concluindo que Deus nos havia chamado para lhes anunciarmos o evangelho.");
    b->dados[ATOS].capitulos[16].versos[11] = wxT("Navegando, pois, de Trôade, fomos em direitura a Samotrácia, e no dia seguinte a Neápolis;");
    b->dados[ATOS].capitulos[16].versos[12] = wxT("e dali para Filipos, que é a primeira cidade desse distrito da Macedônia, e colônia romana; e estivemos alguns dias nessa cidade.");
    b->dados[ATOS].capitulos[16].versos[13] = wxT("No sábado saímos portas afora para a beira do rio, onde julgávamos haver um lugar de oração e, sentados, falávamos às mulheres ali reunidas.");
    b->dados[ATOS].capitulos[16].versos[14] = wxT("E certa mulher chamada Lídia, vendedora de púrpura, da cidade de Tiatira, e que temia a Deus, nos escutava e o Senhor lhe abriu o coração para atender às coisas que Paulo dizia.");
    b->dados[ATOS].capitulos[16].versos[15] = wxT("Depois que foi batizada, ela e a sua casa, rogou-nos, dizendo: Se haveis julgado que eu sou fiel ao Senhor, entrai em minha casa, e ficai ali. E nos constrangeu a isso.");
    b->dados[ATOS].capitulos[16].versos[16] = wxT("Ora, aconteceu que quando íamos ao lugar de oração, nos veio ao encontro uma jovem que tinha um espírito adivinhador, e que, adivinhando, dava grande lucro a seus senhores.");
    b->dados[ATOS].capitulos[16].versos[17] = wxT("Ela, seguindo a Paulo e a nós, clamava, dizendo: São servos do Deus Altíssimo estes homens que vos anunciam um caminho de salvação.");
    b->dados[ATOS].capitulos[16].versos[18] = wxT("E fazia isto por muitos dias. Mas Paulo, perturbado, voltou-se e disse ao espírito: Eu te ordeno em nome de Jesus Cristo que saias dela. E na mesma hora saiu.");
    b->dados[ATOS].capitulos[16].versos[19] = wxT("Ora, vendo seus senhores que a esperança do seu lucro havia desaparecido, prenderam a Paulo e Silas, e os arrastaram para uma praça à presença dos magistrados.");
    b->dados[ATOS].capitulos[16].versos[20] = wxT("E, apresentando-os aos magistrados, disseram: Estes homens, sendo judeus, estão perturbando muito a nossa cidade,");
    b->dados[ATOS].capitulos[16].versos[21] = wxT("e pregam costumes que não nos é lícito receber nem praticar, sendo nós romanos.");
    b->dados[ATOS].capitulos[16].versos[22] = wxT("A multidão levantou-se à uma contra eles, e os magistrados, rasgando-lhes os vestidos, mandaram açoitá-los com varas.");
    b->dados[ATOS].capitulos[16].versos[23] = wxT("E, havendo-lhes dado muitos açoites, os lançaram na prisão, mandando ao carcereiro que os guardasse com segurança.");
    b->dados[ATOS].capitulos[16].versos[24] = wxT("Ele, tendo recebido tal ordem, os lançou na prisão interior e lhes segurou os pés no tronco.");
    b->dados[ATOS].capitulos[16].versos[25] = wxT("Pela meia-noite Paulo e Silas oravam e cantavam hinos a Deus, enquanto os presos os escutavam.");
    b->dados[ATOS].capitulos[16].versos[26] = wxT("De repente houve um tão grande terremoto que foram abalados os alicerces do cárcere, e logo se abriram todas as portas e foram soltos os grilhões de todos.");
    b->dados[ATOS].capitulos[16].versos[27] = wxT("Ora, o carcereiro, tendo acordado e vendo abertas as portas da prisão, tirou a espada e ia suicidar-se, supondo que os presos tivessem fugido.");
    b->dados[ATOS].capitulos[16].versos[28] = wxT("Mas Paulo bradou em alta voz, dizendo: Não te faças nenhum mal, porque todos aqui estamos.");
    b->dados[ATOS].capitulos[16].versos[29] = wxT("Tendo ele pedido luz, saltou dentro e, todo trêmulo, se prostrou ante Paulo e Silas");
    b->dados[ATOS].capitulos[16].versos[30] = wxT("e, tirando-os para fora, disse: Senhores, que me é necessário fazer para me salvar?");
    b->dados[ATOS].capitulos[16].versos[31] = wxT("Responderam eles: Crê no Senhor Jesus e serás salvo, tu e tua casa.");
    b->dados[ATOS].capitulos[16].versos[32] = wxT("Então lhe pregaram a palavra de Deus, e a todos os que estavam em sua casa.");
    b->dados[ATOS].capitulos[16].versos[33] = wxT("Tomando-os ele consigo naquela mesma hora da noite, lavou-lhes as feridas; e logo foi batizado, ele e todos os seus.");
    b->dados[ATOS].capitulos[16].versos[34] = wxT("Então os fez subir para sua casa, pôs-lhes a mesa e alegrou-se muito com toda a sua casa, por ter crido em Deus.");
    b->dados[ATOS].capitulos[16].versos[35] = wxT("Quando amanheceu, os magistrados mandaram quadrilheiros a dizer: Soltai aqueles homens.");
    b->dados[ATOS].capitulos[16].versos[36] = wxT("E o carcereiro transmitiu a Paulo estas palavras, dizendo: Os magistrados mandaram que fosseis soltos; agora, pois, saí e ide em paz.");
    b->dados[ATOS].capitulos[16].versos[37] = wxT("Mas Paulo respondeu-lhes: Açoitaram-nos publicamente sem sermos condenados, sendo cidadãos romanos, e nos lançaram na prisão, e agora encobertamente nos lançam fora? De modo nenhum será assim; mas venham eles mesmos e nos tirem.");
    b->dados[ATOS].capitulos[16].versos[38] = wxT("E os quadrilheiros foram dizer aos magistrados estas palavras, e estes temeram quando ouviram que eles eram romanos;");
    b->dados[ATOS].capitulos[16].versos[39] = wxT("vieram, pediram-lhes desculpas e, tirando-os para fora, rogavam que se retirassem da cidade.");
    b->dados[ATOS].capitulos[16].versos[40] = wxT("Então eles saíram da prisão, entraram em casa de Lídia, e, vendo os irmãos, os confortaram, e partiram.");

    b->dados[ATOS].capitulos[17].versos[1] = wxT("Tendo passado por Anfípolis e Apolônia, chegaram a Tessalônica, onde havia uma sinagoga dos judeus.");
    b->dados[ATOS].capitulos[17].versos[2] = wxT("Ora, Paulo, segundo o seu costume, foi ter com eles; e por três sábados discutiu com eles as Escrituras,");
    b->dados[ATOS].capitulos[17].versos[3] = wxT("expondo e demonstrando que era necessário que o Cristo padecesse e ressuscitasse dentre os mortos; este Jesus que eu vos anuncio, dizia ele, é o Cristo.");
    b->dados[ATOS].capitulos[17].versos[4] = wxT("E alguns deles ficaram persuadidos e aderiram a Paulo e Silas, bem como grande multidão de gregos devotos e não poucas mulheres de posição.");
    b->dados[ATOS].capitulos[17].versos[5] = wxT("Mas os judeus, movidos de inveja, tomando consigo alguns homens maus dentre os vadios e ajuntando o povo, alvoroçavam a cidade e, assaltando a casa de Jáson, os procuravam para entregá-los ao povo.");
    b->dados[ATOS].capitulos[17].versos[6] = wxT("Porém, não os achando, arrastaram Jáson e alguns irmãos à presença dos magistrados da cidade, clamando: Estes que têm transtornado o mundo chegaram também aqui,");
    b->dados[ATOS].capitulos[17].versos[7] = wxT("os quais Jáson acolheu; e todos eles procedem contra os decretos de César, dizendo haver outro rei, que é Jesus.");
    b->dados[ATOS].capitulos[17].versos[8] = wxT("Assim alvoroçaram a multidão e os magistrados da cidade, que ouviram estas coisas.");
    b->dados[ATOS].capitulos[17].versos[9] = wxT("Tendo, porém, recebido fiança de Jáson e dos demais, soltaram-nos.");
    b->dados[ATOS].capitulos[17].versos[10] = wxT("E logo, de noite, os irmãos enviaram Paulo e Silas para Beréia; tendo eles ali chegado, foram à sinagoga dos judeus.");
    b->dados[ATOS].capitulos[17].versos[11] = wxT("Ora, estes eram mais nobres do que os de Tessalônica, porque receberam a palavra com toda avidez, examinando diariamente as Escrituras para ver se estas coisas eram assim.");
    b->dados[ATOS].capitulos[17].versos[12] = wxT("De sorte que muitos deles creram, bem como bom número de mulheres gregas de alta posição e não poucos homens.");
    b->dados[ATOS].capitulos[17].versos[13] = wxT("Mas, logo que os judeus de Tessalônica souberam que também em Beréia era anunciada por Paulo a palavra de Deus, foram lá agitar e sublevar as multidões.");
    b->dados[ATOS].capitulos[17].versos[14] = wxT("Imediatamente os irmãos fizeram sair a Paulo para que fosse até o mar; mas Silas e Timóteo ficaram ali.");
    b->dados[ATOS].capitulos[17].versos[15] = wxT("E os que acompanhavam a Paulo levaram-no até Atenas e, tendo recebido ordem para Silas e Timóteo a fim de que estes fossem ter com ele o mais depressa possível, partiram.");
    b->dados[ATOS].capitulos[17].versos[16] = wxT("Enquanto Paulo os esperava em Atenas, revoltava-se nele o seu espírito, vendo a cidade cheia de ídolos.");
    b->dados[ATOS].capitulos[17].versos[17] = wxT("Argumentava, portanto, na sinagoga com os judeus e os gregos devotos, e na praça todos os dias com os que se encontravam ali.");
    b->dados[ATOS].capitulos[17].versos[18] = wxT("Ora, alguns filósofos epicureus e estóicos disputavam com ele. Uns diziam: Que quer dizer este paroleiro? E outros: Parece ser pregador de deuses estranhos; pois anunciava a boa nova de Jesus e a ressurreição.");
    b->dados[ATOS].capitulos[17].versos[19] = wxT("E, tomando-o, o levaram ao Areópago, dizendo: Poderemos nós saber que nova doutrina é essa de que falas?");
    b->dados[ATOS].capitulos[17].versos[20] = wxT("Pois tu nos trazes aos ouvidos coisas estranhas; portanto queremos saber o que vem a ser isto.");
    b->dados[ATOS].capitulos[17].versos[21] = wxT("Ora, todos os atenienses, como também os estrangeiros que ali residiam, de nenhuma outra coisa se ocupavam senão de contar ou de ouvir a última novidade.");
    b->dados[ATOS].capitulos[17].versos[22] = wxT("Então Paulo, estando de pé no meio do Areópago, disse: Varões atenienses, em tudo vejo que sois excepcionalmente religiosos;");
    b->dados[ATOS].capitulos[17].versos[23] = wxT("porque, passando eu e observando os objetos do vosso culto, encontrei também um altar em que estava escrito: AO DEUS DESCONHECIDO. Esse, pois, que vós honrais sem o conhecer, é o que vos anuncio.");
    b->dados[ATOS].capitulos[17].versos[24] = wxT("O Deus que fez o mundo e tudo o que nele há, sendo ele Senhor do céu e da terra, não habita em templos feitos por mãos de homens;");
    b->dados[ATOS].capitulos[17].versos[25] = wxT("nem tampouco é servido por mãos humanas, como se necessitasse de alguma coisa; pois ele mesmo é quem dá a todos a vida, a respiração e todas as coisas;");
    b->dados[ATOS].capitulos[17].versos[26] = wxT("e de um só fez todas as raças dos homens, para habitarem sobre toda a face da terra, determinando-lhes os tempos já dantes ordenados e os limites da sua habitação;");
    b->dados[ATOS].capitulos[17].versos[27] = wxT("para que buscassem a Deus, se porventura, tateando, o pudessem achar, o qual, todavia, não está longe de cada um de nós;");
    b->dados[ATOS].capitulos[17].versos[28] = wxT("porque nele vivemos, e nos movemos, e existimos; como também alguns dos vossos poetas disseram: Pois dele também somos geração.");
    b->dados[ATOS].capitulos[17].versos[29] = wxT("Sendo nós, pois, geração de Deus, não devemos pensar que a divindade seja semelhante ao ouro, ou à prata, ou à pedra esculpida pela arte e imaginação do homem.");
    b->dados[ATOS].capitulos[17].versos[30] = wxT("Mas Deus, não levando em conta os tempos da ignorância, manda agora que todos os homens em todo lugar se arrependam;");
    b->dados[ATOS].capitulos[17].versos[31] = wxT("porquanto determinou um dia em que com justiça há de julgar o mundo, por meio do varão que para isso ordenou; e disso tem dado certeza a todos, ressuscitando-o dentre os mortos.");
    b->dados[ATOS].capitulos[17].versos[32] = wxT("Mas quando ouviram falar em ressurreição de mortos, uns escarneciam, e outros diziam: Acerca disso te ouviremos ainda outra vez.");
    b->dados[ATOS].capitulos[17].versos[33] = wxT("Assim Paulo saiu do meio deles.");
    b->dados[ATOS].capitulos[17].versos[34] = wxT("Todavia, alguns homens aderiram a ele, e creram, entre os quais Dionísio, o areopagita, e uma mulher por nome Dâmaris, e com eles outros.");

    b->dados[ATOS].capitulos[18].versos[1] = wxT("Depois disto Paulo partiu de Atenas e chegou a Corinto.");
    b->dados[ATOS].capitulos[18].versos[2] = wxT("E encontrando um judeu por nome Áqüila, natural do Ponto, que pouco antes viera da Itália, e Priscila, sua mulher {porque Cláudio tinha decretado que todos os judeus saíssem de Roma}, foi ter com eles,");
    b->dados[ATOS].capitulos[18].versos[3] = wxT("e, por ser do mesmo ofício, com eles morava, e juntos trabalhavam; pois eram, por ofício, fabricantes de tendas.");
    b->dados[ATOS].capitulos[18].versos[4] = wxT("Ele discutia todos os sábados na sinagoga, e persuadia a judeus e gregos.");
    b->dados[ATOS].capitulos[18].versos[5] = wxT("Quando Silas e Timóteo desceram da Macedônia, Paulo dedicou-se inteiramente à palavra, testificando aos judeus que Jesus era o Cristo.");
    b->dados[ATOS].capitulos[18].versos[6] = wxT("Como estes, porém, se opusessem e proferissem injúrias, sacudiu ele as vestes e disse-lhes: O vosso sangue seja sobre a vossa cabeça; eu estou limpo, e desde agora vou para os gentios.");
    b->dados[ATOS].capitulos[18].versos[7] = wxT("E saindo dali, entrou em casa de um homem temente a Deus, chamado Tito Justo, cuja casa ficava junto da sinagoga.");
    b->dados[ATOS].capitulos[18].versos[8] = wxT("Crispo, chefe da sinagoga, creu no Senhor com toda a sua casa; e muitos dos coríntios, ouvindo, criam e eram batizados.");
    b->dados[ATOS].capitulos[18].versos[9] = wxT("E de noite disse o Senhor em visão a Paulo: Não temas, mas fala e não te cales;");
    b->dados[ATOS].capitulos[18].versos[10] = wxT("porque eu estou contigo e ninguém te acometerá para te fazer mal, pois tenho muito povo nesta cidade.");
    b->dados[ATOS].capitulos[18].versos[11] = wxT("E ficou ali um ano e seis meses, ensinando entre eles a palavra de Deus.");
    b->dados[ATOS].capitulos[18].versos[12] = wxT("Sendo Gálio procônsul da Acaia, levantaram-se os judeus de comum acordo contra Paulo, e o levaram ao tribunal,");
    b->dados[ATOS].capitulos[18].versos[13] = wxT("dizendo: Este persuade os homens a render culto a Deus de um modo contrário à lei.");
    b->dados[ATOS].capitulos[18].versos[14] = wxT("E, quando Paulo estava para abrir a boca, disse Gálio aos judeus: Se de fato houvesse, ó judeus, algum agravo ou crime perverso, com razão eu vos sofreria;");
    b->dados[ATOS].capitulos[18].versos[15] = wxT("mas, se são questões de palavras, de nomes, e da vossa lei, disso cuidai vós mesmos; porque eu não quero ser juiz destas coisas.");
    b->dados[ATOS].capitulos[18].versos[16] = wxT("E expulsou-os do tribunal.");
    b->dados[ATOS].capitulos[18].versos[17] = wxT("Então todos agarraram Sóstenes, chefe da sinagoga, e o espancavam diante do tribunal; e Gálio não se importava com nenhuma dessas coisas.");
    b->dados[ATOS].capitulos[18].versos[18] = wxT("Paulo, tendo ficado ali ainda muitos dias, despediu-se dos irmãos e navegou para a Síria, e com ele Priscila e Áqüila, havendo rapado a cabeça em Cencréia, porque tinha voto.");
    b->dados[ATOS].capitulos[18].versos[19] = wxT("E eles chegaram a Éfeso, onde Paulo os deixou; e tendo entrado na sinagoga, discutia com os judeus.");
    b->dados[ATOS].capitulos[18].versos[20] = wxT("Estes rogavam que ficasse por mais algum tempo, mas ele não anuiu,");
    b->dados[ATOS].capitulos[18].versos[21] = wxT("antes se despediu deles, dizendo: Se Deus quiser, de novo voltarei a vós; e navegou de Éfeso.");
    b->dados[ATOS].capitulos[18].versos[22] = wxT("Tendo chegado a Cesaréia, subiu a Jerusalém e saudou a igreja, e desceu a Antioquia.");
    b->dados[ATOS].capitulos[18].versos[23] = wxT("E, tendo demorado ali algum tempo, partiu, passando sucessivamente pela região da Galácia e da Frígia, fortalecendo a todos os discípulos.");
    b->dados[ATOS].capitulos[18].versos[24] = wxT("Ora, chegou a Éfeso certo judeu chamado Apolo, natural de Alexandria, homem eloqüente e poderoso nas Escrituras.");
    b->dados[ATOS].capitulos[18].versos[25] = wxT("Era ele instruído no caminho do Senhor e, sendo fervoroso de espírito, falava e ensinava com precisão as coisas concernentes a Jesus, conhecendo entretanto somente o batismo de João.");
    b->dados[ATOS].capitulos[18].versos[26] = wxT("Ele começou a falar ousadamente na sinagoga: mas quando Priscila e Áqüila o ouviram, levaram-no consigo e lhe expuseram com mais precisão o caminho de Deus.");
    b->dados[ATOS].capitulos[18].versos[27] = wxT("Querendo ele passar à Acáia, os irmãos o animaram e escreveram aos discípulos que o recebessem; e tendo ele chegado, auxiliou muito aos que pela graça haviam crido.");
    b->dados[ATOS].capitulos[18].versos[28] = wxT("Pois com grande poder refutava publicamente os judeus, demonstrando pelas escrituras que Jesus era o Cristo.");

    b->dados[ATOS].capitulos[19].versos[1] = wxT("E sucedeu que, enquanto Apolo estava em Corinto, Paulo tendo atravessado as regiões mais altas, chegou a Éfeso e, achando ali alguns discípulos,");
    b->dados[ATOS].capitulos[19].versos[2] = wxT("perguntou-lhes: Recebestes vós o Espírito Santo quando crestes? Responderam-lhe eles: Não, nem sequer ouvimos que haja Espírito Santo.");
    b->dados[ATOS].capitulos[19].versos[3] = wxT("Tornou-lhes ele: Em que fostes batizados então? E eles disseram: No batismo de João.");
    b->dados[ATOS].capitulos[19].versos[4] = wxT("Mas Paulo respondeu: João administrou o batismo do arrependimento, dizendo ao povo que cresse naquele que após ele havia de vir, isto é, em Jesus.");
    b->dados[ATOS].capitulos[19].versos[5] = wxT("Quando ouviram isso, foram batizados em nome do Senhor Jesus.");
    b->dados[ATOS].capitulos[19].versos[6] = wxT("Havendo-lhes Paulo imposto as mãos, veio sobre eles o Espírito Santo, e falavam em línguas e profetizavam.");
    b->dados[ATOS].capitulos[19].versos[7] = wxT("E eram ao todo uns doze homens.");
    b->dados[ATOS].capitulos[19].versos[8] = wxT("Paulo, entrando na sinagoga, falou ousadamente por espaço de três meses, discutindo e persuadindo acerca do reino de Deus.");
    b->dados[ATOS].capitulos[19].versos[9] = wxT("Mas, como alguns deles se endurecessem e não obedecessem, falando mal do Caminho diante da multidão, apartou-se deles e separou os discípulos, discutindo diariamente na escola de Tirano.");
    b->dados[ATOS].capitulos[19].versos[10] = wxT("Durou isto por dois anos; de maneira que todos os que habitavam na Ásia, tanto judeus como gregos, ouviram a palavra do Senhor.");
    b->dados[ATOS].capitulos[19].versos[11] = wxT("E Deus pelas mãos de Paulo fazia milagres extraordinários,");
    b->dados[ATOS].capitulos[19].versos[12] = wxT("de sorte que lenços e aventais eram levados do seu corpo aos enfermos, e as doenças os deixavam e saíam deles os espíritos malignos.");
    b->dados[ATOS].capitulos[19].versos[13] = wxT("Ora, também alguns dos exorcistas judeus, ambulantes, tentavam invocar o nome de Jesus sobre os que tinham espíritos malignos, dizendo: Esconjuro-vos por Jesus a quem Paulo prega.");
    b->dados[ATOS].capitulos[19].versos[14] = wxT("E os que faziam isto eram sete filhos de Ceva, judeu, um dos principais sacerdotes.");
    b->dados[ATOS].capitulos[19].versos[15] = wxT("Respondendo, porém, o espírito maligno, disse: A Jesus conheço, e sei quem é Paulo; mas vós, quem sois?");
    b->dados[ATOS].capitulos[19].versos[16] = wxT("Então o homem, no qual estava o espírito maligno, saltando sobre eles, apoderou-se de dois e prevaleceu contra eles, de modo que, nus e feridos, fugiram daquela casa.");
    b->dados[ATOS].capitulos[19].versos[17] = wxT("E isto tornou-se conhecido de todos os que moravam em Éfeso, tanto judeus como gregos; e veio temor sobre todos eles, e o nome do Senhor Jesus era engrandecido.");
    b->dados[ATOS].capitulos[19].versos[18] = wxT("E muitos dos que haviam crido vinham, confessando e revelando os seus feitos.");
    b->dados[ATOS].capitulos[19].versos[19] = wxT("Muitos também dos que tinham praticado artes mágicas ajuntaram os seus livros e os queimaram na presença de todos; e, calculando o valor deles, acharam que montava a cinqüenta mil moedas de prata.");
    b->dados[ATOS].capitulos[19].versos[20] = wxT("Assim a palavra do Senhor crescia poderosamente e prevalecia.");
    b->dados[ATOS].capitulos[19].versos[21] = wxT("Cumpridas estas coisas, Paulo propôs, em seu espírito, ir a Jerusalém, passando pela Macedônia e pela Acaia, porque dizia: Depois de haver estado ali, é-me necessário ver também Roma.");
    b->dados[ATOS].capitulos[19].versos[22] = wxT("E, enviando à Macedônia dois dos que o auxiliavam, Timóteo e Erasto, ficou ele por algum tempo na Ásia.");
    b->dados[ATOS].capitulos[19].versos[23] = wxT("Por esse tempo houve um não pequeno alvoroço acerca do Caminho.");
    b->dados[ATOS].capitulos[19].versos[24] = wxT("Porque certo ourives, por nome Demétrio, que fazia da prata miniaturas do templo de Diana, proporcionava não pequeno negócio aos artífices,");
    b->dados[ATOS].capitulos[19].versos[25] = wxT("os quais ele ajuntou, bem como os oficiais de obras semelhantes, e disse: Senhores, vós bem sabeis que desta indústria nos vem a prosperidade,");
    b->dados[ATOS].capitulos[19].versos[26] = wxT("e estais vendo e ouvindo que não é só em Éfeso, mas em quase toda a Ásia, este Paulo tem persuadido e desviado muita gente, dizendo não serem deuses os que são feitos por mãos humanas.");
    b->dados[ATOS].capitulos[19].versos[27] = wxT("E não somente há perigo de que esta nossa profissão caia em descrédito, mas também que o templo da grande deusa Diana seja estimado em nada, vindo mesmo a ser destituída da sua majestade aquela a quem toda a Ásia e o mundo adoram.");
    b->dados[ATOS].capitulos[19].versos[28] = wxT("Ao ouvirem isso, encheram-se de ira, e clamavam, dizendo: Grande é a Diana dos efésios!");
    b->dados[ATOS].capitulos[19].versos[29] = wxT("A cidade encheu-se de confusão, e todos à uma correram ao teatro, arrebatando a Gaio e a Aristarco, macedônios, companheiros de Paulo na viagem.");
    b->dados[ATOS].capitulos[19].versos[30] = wxT("Querendo Paulo apresentar-se ao povo, os discípulos não lho permitiram.");
    b->dados[ATOS].capitulos[19].versos[31] = wxT("Também alguns dos asiarcas, sendo amigos dele, mandaram rogar-lhe que não se arriscasse a ir ao teatro.");
    b->dados[ATOS].capitulos[19].versos[32] = wxT("Uns, pois, gritavam de um modo, outros de outro; porque a assembléia estava em confusão, e a maior parte deles nem sabia por que causa se tinham ajuntado.");
    b->dados[ATOS].capitulos[19].versos[33] = wxT("Então tiraram dentre a turba a Alexandre, a quem os judeus impeliram para a frente; e Alexandre, acenando com a mão, queria apresentar uma defesa ao povo.");
    b->dados[ATOS].capitulos[19].versos[34] = wxT("Mas quando perceberam que ele era judeu, todos a uma voz gritaram por quase duas horas: Grande é a Diana dos efésios!");
    b->dados[ATOS].capitulos[19].versos[35] = wxT("Havendo o escrivão conseguido apaziguar a turba, disse: Varões efésios, que homem há que não saiba que a cidade dos efésios é a guardadora do templo da grande deusa Diana, e da imagem que caiu de Júpiter?");
    b->dados[ATOS].capitulos[19].versos[36] = wxT("Ora, visto que estas coisas não podem ser contestadas, convém que vos aquieteis e nada façais precipitadamente.");
    b->dados[ATOS].capitulos[19].versos[37] = wxT("Porque estes homens que aqui trouxestes, nem são sacrílegos nem blasfemadores da nossa deusa.");
    b->dados[ATOS].capitulos[19].versos[38] = wxT("Todavia, se Demétrio e os artífices que estão com ele têm alguma queixa contra alguém, os tribunais estão abertos e há procônsules: que se acusem uns aos outros.");
    b->dados[ATOS].capitulos[19].versos[39] = wxT("E se demandais alguma outra coisa, averiguar-se-á em legítima assembléia.");
    b->dados[ATOS].capitulos[19].versos[40] = wxT("Pois até corremos perigo de sermos acusados de sedição pelos acontecimentos de hoje, não havendo motivo algum com que possamos justificar este ajuntamento.");
    b->dados[ATOS].capitulos[19].versos[41] = wxT("E, tendo dito isto, despediu a assembléia.");

    b->dados[ATOS].capitulos[20].versos[1] = wxT("Depois que cessou o alvoroço, Paulo mandou chamar os discípulos e, tendo-os exortado, despediu-se e partiu para a Macedônia.");
    b->dados[ATOS].capitulos[20].versos[2] = wxT("E, havendo andado por aquelas regiões, exortando os discípulos com muitas palavras, veio à Grécia.");
    b->dados[ATOS].capitulos[20].versos[3] = wxT("Depois de passar ali três meses, visto terem os judeus armado uma cilada contra ele quando ia embarcar para a Síria, determinou voltar pela Macedônia.");
    b->dados[ATOS].capitulos[20].versos[4] = wxT("Acompanhou-o Sópater de Beréia, filho de Pirro; bem como dos de Tessalônica, Aristarco e Segundo; Gaio de Derbe e Timóteo; e dos da Ásia, Tíquico e Trófimo.");
    b->dados[ATOS].capitulos[20].versos[5] = wxT("Estes porém, foram adiante e nos esperavam em Trôade.");
    b->dados[ATOS].capitulos[20].versos[6] = wxT("E nós, depois dos dias dos pães ázimos, navegamos de Filipos, e em cinco dias fomos ter com eles em Trôade, onde nos detivemos sete dias.");
    b->dados[ATOS].capitulos[20].versos[7] = wxT("No primeiro dia da semana, tendo-nos reunido a fim de partir o pão, Paulo, que havia de sair no dia seguinte, falava com eles, e prolongou o seu discurso até a meia-noite.");
    b->dados[ATOS].capitulos[20].versos[8] = wxT("Ora, havia muitas luzes no cenáculo onde estávamos reunidos.");
    b->dados[ATOS].capitulos[20].versos[9] = wxT("E certo jovem, por nome Êutico, que estava sentado na janela, tomado de um sono profundo enquanto Paulo prolongava ainda mais o seu sermão, vencido pelo sono caiu do terceiro andar abaixo, e foi levantado morto.");
    b->dados[ATOS].capitulos[20].versos[10] = wxT("Tendo Paulo descido, debruçou-se sobre ele e, abraçando-o, disse: Não vos perturbeis, pois a sua alma está nele.");
    b->dados[ATOS].capitulos[20].versos[11] = wxT("Então subiu, e tendo partido o pão e comido, ainda lhes falou largamente até o romper do dia; e assim partiu.");
    b->dados[ATOS].capitulos[20].versos[12] = wxT("E levaram vivo o jovem e ficaram muito consolados.");
    b->dados[ATOS].capitulos[20].versos[13] = wxT("Nós, porém, tomando a dianteira e embarcando, navegamos para Assôs, onde devíamos receber a Paulo, porque ele, havendo de ir por terra, assim o ordenara.");
    b->dados[ATOS].capitulos[20].versos[14] = wxT("E, logo que nos alcançou em Assôs, recebemo-lo a bordo e fomos a Mitilene;");
    b->dados[ATOS].capitulos[20].versos[15] = wxT("e navegando dali, chegamos no dia imediato defronte de Quios, no outro aportamos a Samos e {e tendo-nos demorado em Trogílio, chegamos,} no dia seguinte a Mileto.");
    b->dados[ATOS].capitulos[20].versos[16] = wxT("Porque Paulo havia determinado passar ao largo de Éfeso, para não se demorar na Ásia; pois se apressava para estar em Jerusalém no dia de Pentecostes, se lhe fosse possível.");
    b->dados[ATOS].capitulos[20].versos[17] = wxT("De Mileto mandou a Éfeso chamar os anciãos da igreja.");
    b->dados[ATOS].capitulos[20].versos[18] = wxT("E, tendo eles chegado, disse-lhes: Vós bem sabeis de que modo me tenho portado entre vós sempre, desde o primeiro dia em que entrei na Ásia,");
    b->dados[ATOS].capitulos[20].versos[19] = wxT("servindo ao Senhor com toda a humildade, e com lágrimas e provações que pelas ciladas dos judeus me sobrevieram;");
    b->dados[ATOS].capitulos[20].versos[20] = wxT("como não me esquivei de vos anunciar coisa alguma que útil seja, ensinando-vos publicamente e de casa em casa,");
    b->dados[ATOS].capitulos[20].versos[21] = wxT("testificando, tanto a judeus como a gregos, o arrependimento para com Deus e a fé em nosso Senhor Jesus.");
    b->dados[ATOS].capitulos[20].versos[22] = wxT("Agora, eis que eu, constrangido no meu espírito, vou a Jerusalém, não sabendo o que ali acontecerá,");
    b->dados[ATOS].capitulos[20].versos[23] = wxT("senão o que o Espírito Santo me testifica, de cidade em cidade, dizendo que me esperam prisões e tribulações,");
    b->dados[ATOS].capitulos[20].versos[24] = wxT("mas em nada tenho a minha vida como preciosa para mim, contando que complete a minha carreira e o ministério que recebi do Senhor Jesus, para dar testemunho do evangelho da graça de Deus.");
    b->dados[ATOS].capitulos[20].versos[25] = wxT("E eis agora, sei que nenhum de vós, por entre os quais passei pregando o reino de Deus, jamais tornará a ver o meu rosto.");
    b->dados[ATOS].capitulos[20].versos[26] = wxT("Portanto, no dia de hoje, vos protesto que estou limpo do sangue de todos.");
    b->dados[ATOS].capitulos[20].versos[27] = wxT("Porque não me esquivei de vos anunciar todo o conselho de Deus.");
    b->dados[ATOS].capitulos[20].versos[28] = wxT("Cuidai pois de vós mesmos e de todo o rebanho sobre o qual o Espírito Santo vos constituiu bispos, para apascentardes a igreja de Deus, que ele adquiriu com seu próprio sangue.");
    b->dados[ATOS].capitulos[20].versos[29] = wxT("Eu sei que depois da minha partida entrarão no meio de vós lobos cruéis que não pouparão rebanho,");
    b->dados[ATOS].capitulos[20].versos[30] = wxT("e que dentre vós mesmos se levantarão homens, falando coisas perversas para atrair os discípulos após si.");
    b->dados[ATOS].capitulos[20].versos[31] = wxT("Portanto vigiai, lembrando-vos de que por três anos não cessei noite e dia de admoestar com lágrimas a cada um de vós.");
    b->dados[ATOS].capitulos[20].versos[32] = wxT("Agora pois, vos encomendo a Deus e à palavra da sua graça, àquele que é poderoso para vos edificar e dar herança entre todos os que são santificados.");
    b->dados[ATOS].capitulos[20].versos[33] = wxT("De ninguém cobicei prata, nem ouro, nem vestes.");
    b->dados[ATOS].capitulos[20].versos[34] = wxT("Vós mesmos sabeis que estas mãos proveram as minhas necessidades e as dos que estavam comigo.");
    b->dados[ATOS].capitulos[20].versos[35] = wxT("Em tudo vos dei o exemplo de que assim trabalhando, é necessário socorrer os enfermos, recordando as palavras do Senhor Jesus, porquanto ele mesmo disse: Coisa mais bem-aventurada é dar do que receber.");
    b->dados[ATOS].capitulos[20].versos[36] = wxT("Havendo dito isto, pôs-se de joelhos, e orou com todos eles.");
    b->dados[ATOS].capitulos[20].versos[37] = wxT("E levantou-se um grande pranto entre todos, e lançando-se ao pescoço de Paulo, beijavam-no.");
    b->dados[ATOS].capitulos[20].versos[38] = wxT("Entristecendo-se principalmente pela palavra que dissera, que não veriam mais o seu rosto. E eles o acompanharam até o navio.");

    b->dados[ATOS].capitulos[21].versos[1] = wxT("E assim aconteceu que, separando-nos deles, navegamos e, correndo em direitura, chegamos a Cós, e no dia seguinte a Rodes, e dali a Pátara.");
    b->dados[ATOS].capitulos[21].versos[2] = wxT("Achando um navio que seguia para a Fenícia, embarcamos e partimos.");
    b->dados[ATOS].capitulos[21].versos[3] = wxT("E quando avistamos Chipre, deixando-a á esquerda, navegamos para a Síria e chegamos a Tiro, pois o navio havia de ser descarregado ali.");
    b->dados[ATOS].capitulos[21].versos[4] = wxT("Havendo achado os discípulos, demoramo-nos ali sete dias; e eles pelo Espírito diziam a Paulo que não subisse a Jerusalém.");
    b->dados[ATOS].capitulos[21].versos[5] = wxT("Depois de passarmos ali aqueles dias, saímos e seguimos a nossa viagem, acompanhando-nos todos, com suas mulheres e filhos, até fora da cidade; e, postos de joelhos na praia, oramos,");
    b->dados[ATOS].capitulos[21].versos[6] = wxT("e despedindo-nos uns dos outros, embarcamos, e eles voltaram para casa.");
    b->dados[ATOS].capitulos[21].versos[7] = wxT("Concluída a nossa viagem de Tiro, chegamos a Ptolemaida; e, havendo saudado os irmãos, passamos um dia com eles.");
    b->dados[ATOS].capitulos[21].versos[8] = wxT("Partindo no dia seguinte, fomos a Cesaréia; e entrando em casa de Felipe, o evangelista, que era um dos sete, ficamos com ele.");
    b->dados[ATOS].capitulos[21].versos[9] = wxT("Tinha este quatro filhas virgens que profetizavam.");
    b->dados[ATOS].capitulos[21].versos[10] = wxT("Demorando-nos ali por muitos dias, desceu da Judéia um profeta, de nome Ágabo;");
    b->dados[ATOS].capitulos[21].versos[11] = wxT("e vindo ter conosco, tomou a cinta de Paulo e, ligando os seus próprios pés e mãos, disse: Isto diz o Espírito Santo: Assim os judeus ligarão em Jerusalém o homem a quem pertence esta cinta, e o entregarão nas mãos dos gentios.");
    b->dados[ATOS].capitulos[21].versos[12] = wxT("Quando ouvimos isto, rogamos-lhe, tanto nós como os daquele lugar, que não subisse a Jerusalém.");
    b->dados[ATOS].capitulos[21].versos[13] = wxT("Então Paulo respondeu: Que fazeis chorando e magoando-me o coração? Porque eu estou pronto não só a ser ligado, mas ainda a morrer em Jerusalém pelo nome do Senhor Jesus.");
    b->dados[ATOS].capitulos[21].versos[14] = wxT("E, como não se deixasse persuadir, dissemos: Faça-se a vontade do Senhor; e calamo-nos.");
    b->dados[ATOS].capitulos[21].versos[15] = wxT("Depois destes dias, havendo feito os preparativos, fomos subindo a Jerusalém.");
    b->dados[ATOS].capitulos[21].versos[16] = wxT("E foram também conosco alguns discípulos de Cesaréia, levando consigo um certo Mnáson, cíprio, discípulo antigo, com quem nos havíamos de hospedar.");
    b->dados[ATOS].capitulos[21].versos[17] = wxT("E chegando nós a Jerusalém, os irmãos nos receberam alegremente.");
    b->dados[ATOS].capitulos[21].versos[18] = wxT("No dia seguinte Paulo foi em nossa companhia ter com Tiago, e compareceram todos os anciãos.");
    b->dados[ATOS].capitulos[21].versos[19] = wxT("E, havendo-os saudado, contou-lhes uma por uma as coisas que por seu ministério Deus fizera entre os gentios.");
    b->dados[ATOS].capitulos[21].versos[20] = wxT("Ouvindo eles isto, glorificaram a Deus, e disseram-lhe: Bem vês, irmãos, quantos milhares há entre os judeus que têm crido, e todos são zelosos da lei.");
    b->dados[ATOS].capitulos[21].versos[21] = wxT("Têm sido informados a teu respeito que ensinas todos os judeus que estão entre os gentios a se apartarem de Moisés, dizendo que não circuncidem seus filhos, nem andem segundo os costumes da lei.");
    b->dados[ATOS].capitulos[21].versos[22] = wxT("Que se há de fazer, pois? Certamente saberão que és chegado.");
    b->dados[ATOS].capitulos[21].versos[23] = wxT("Faze, pois, o que te vamos dizer: Temos quatro homens que fizeram voto;");
    b->dados[ATOS].capitulos[21].versos[24] = wxT("toma estes contigo, e santifica-te com eles, e faze por eles as despesas para que rapem a cabeça; e saberão todos que é falso aquilo de que têm sido informados a teu respeito, mas que também tu mesmo andas corretamente, guardando a lei.");
    b->dados[ATOS].capitulos[21].versos[25] = wxT("Todavia, quanto aos gentios que têm crido já escrevemos, dando o parecer que se abstenham do que é sacrificado a os ídolos, do sangue, do sufocado e da prostituição.");
    b->dados[ATOS].capitulos[21].versos[26] = wxT("Então Paulo, no dia seguinte, tomando consigo aqueles homens, purificou-se com eles e entrou no templo, notificando o cumprimento dos dias da purificação, quando seria feita a favor de cada um deles a respectiva oferta.");
    b->dados[ATOS].capitulos[21].versos[27] = wxT("Mas quando os sete dias estavam quase a terminar, os judeus da Ásia, tendo-o visto no templo, alvoroçaram todo o povo e agarraram-no,");
    b->dados[ATOS].capitulos[21].versos[28] = wxT("clamando: Varões israelitas, acudi; este é o homem que por toda parte ensina a todos contra o povo, contra a lei, e contra este lugar; e ainda, além disso, introduziu gregos no templo, e tem profanado este santo lugar.");
    b->dados[ATOS].capitulos[21].versos[29] = wxT("Antes tinham visto com ele na cidade a Trófimo de Éfeso, e pensavam que Paulo o introduzira no templo.");
    b->dados[ATOS].capitulos[21].versos[30] = wxT("Alvoroçou-se toda a cidade, e houve ajuntamento do povo; e agarrando a Paulo, arrastaram-no para fora do templo, e logo as portas se fecharam.");
    b->dados[ATOS].capitulos[21].versos[31] = wxT("E, procurando eles matá-lo, chegou ao comandante da corte o aviso de que Jerusalém estava toda em confusão;");
    b->dados[ATOS].capitulos[21].versos[32] = wxT("o qual, tomando logo consigo soldados e centuriões, correu para eles; e quando viram o comandante e os soldados, cessaram de espancar a Paulo.");
    b->dados[ATOS].capitulos[21].versos[33] = wxT("Então aproximando-se o comandante, prendeu-o e mandou que fosse acorrentado com duas cadeias, e perguntou quem era e o que tinha feito.");
    b->dados[ATOS].capitulos[21].versos[34] = wxT("E na multidão uns gritavam de um modo, outros de outro; mas, não podendo por causa do alvoroço saber a verdade, mandou conduzi-lo à fortaleza.");
    b->dados[ATOS].capitulos[21].versos[35] = wxT("E sucedeu que, chegando às escadas, foi ele carregado pelos soldados por causa da violência da turba.");
    b->dados[ATOS].capitulos[21].versos[36] = wxT("Pois a multidão o seguia, clamando: Mata-o!");
    b->dados[ATOS].capitulos[21].versos[37] = wxT("Quando estava para ser introduzido na fortaleza, disse Paulo ao comandante: É-me permitido dizer-te alguma coisa? Respondeu ele: Sabes o grego?");
    b->dados[ATOS].capitulos[21].versos[38] = wxT("Não és porventura o egípcio que há poucos dias fez uma sedição e levou ao deserto os quatro mil sicários?");
    b->dados[ATOS].capitulos[21].versos[39] = wxT("Mas Paulo lhe disse: Eu sou judeu, natural de Tarso, cidade não insignificante da Cilícia; rogo-te que me permitas falar ao povo.");
    b->dados[ATOS].capitulos[21].versos[40] = wxT("E, havendo-lho permitido o comandante, Paulo, em pé na escada, fez sinal ao povo com a mão; e, feito grande silêncio, falou em língua hebraica, dizendo:");

    b->dados[ATOS].capitulos[22].versos[1] = wxT("Irmãos e pais, ouvi a minha defesa, que agora faço perante vós.");
    b->dados[ATOS].capitulos[22].versos[2] = wxT("Ora, quando ouviram que lhes falava em língua hebraica, guardaram ainda maior silêncio. E ele prosseguiu:");
    b->dados[ATOS].capitulos[22].versos[3] = wxT("Eu sou judeu, nascido em Tarso da Cilícia, mas criado nesta cidade, instruído aos pés de Gamaliel, conforme a precisão da lei de nossos pais, sendo zeloso para com Deus, assim como o sois todos vós no dia de hoje.");
    b->dados[ATOS].capitulos[22].versos[4] = wxT("E persegui este Caminho até a morte, algemando e metendo em prisões tanto a homens como a mulheres,");
    b->dados[ATOS].capitulos[22].versos[5] = wxT("do que também o sumo sacerdote me é testemunha, e assim todo o conselho dos anciãos; e, tendo recebido destes cartas para os irmãos, seguia para Damasco, com o fim de trazer algemados a Jerusalém aqueles que ali estivessem, para que fossem castigados.");
    b->dados[ATOS].capitulos[22].versos[6] = wxT("Aconteceu, porém, que, quando caminhava e ia chegando perto de Damasco, pelo meio-dia, de repente, do céu brilhou-me ao redor uma grande luz.");
    b->dados[ATOS].capitulos[22].versos[7] = wxT("Caí por terra e ouvi uma voz que me dizia: Saulo, Saulo, por que me persegues?");
    b->dados[ATOS].capitulos[22].versos[8] = wxT("Eu respondi: Quem és tu, Senhor? Disse-me: Eu sou Jesus, o nazareno, a quem tu persegues.");
    b->dados[ATOS].capitulos[22].versos[9] = wxT("E os que estavam comigo viram, em verdade, a luz, mas não entenderam a voz daquele que falava comigo.");
    b->dados[ATOS].capitulos[22].versos[10] = wxT("Então perguntei: Senhor que farei? E o Senhor me disse: Levanta-te, e vai a Damasco, onde se te dirá tudo o que te é ordenado fazer.");
    b->dados[ATOS].capitulos[22].versos[11] = wxT("Como eu nada visse por causa do esplendor daquela luz, guiado pela mão dos que estavam comigo cheguei a Damasco.");
    b->dados[ATOS].capitulos[22].versos[12] = wxT("Um certo Ananias, varão piedoso conforme a lei, que tinha bom testemunho de todos os judeus que ali moravam,");
    b->dados[ATOS].capitulos[22].versos[13] = wxT("vindo ter comigo, de pé ao meu lado, disse-me: Saulo, irmão, recobra a vista. Naquela mesma hora, recobrando a vista, eu o vi.");
    b->dados[ATOS].capitulos[22].versos[14] = wxT("Disse ele: O Deus de nossos pais de antemão te designou para conhecer a sua vontade, ver o Justo, e ouvir a voz da sua boca.");
    b->dados[ATOS].capitulos[22].versos[15] = wxT("Porque hás de ser sua testemunha para com todos os homens do que tens visto e ouvido.");
    b->dados[ATOS].capitulos[22].versos[16] = wxT("Agora por que te demoras? Levanta-te, batiza-te e lava os teus pecados, invocando o seu nome.");
    b->dados[ATOS].capitulos[22].versos[17] = wxT("Aconteceu que, tendo eu voltado para Jerusalém, enquanto orava no templo, achei-me em êxtase,");
    b->dados[ATOS].capitulos[22].versos[18] = wxT("e vi aquele que me dizia: Apressa-te e sai logo de Jerusalém; porque não receberão o teu testemunho acerca de mim.");
    b->dados[ATOS].capitulos[22].versos[19] = wxT("Disse eu: Senhor, eles bem sabem que eu encarcerava e açoitava pelas sinagogas os que criam em ti.");
    b->dados[ATOS].capitulos[22].versos[20] = wxT("E quando se derramava o sangue de Estêvão, tua testemunha, eu também estava presente, consentindo na sua morte e guardando as capas dos que o matavam.");
    b->dados[ATOS].capitulos[22].versos[21] = wxT("Disse-me ele: Vai, porque eu te enviarei para longe, aos gentios.");
    b->dados[ATOS].capitulos[22].versos[22] = wxT("Ora, escutavam-no até esta palavra, mas então levantaram a voz, dizendo: Tira do mundo tal homem, porque não convém que viva.");
    b->dados[ATOS].capitulos[22].versos[23] = wxT("Gritando eles e arrojando de si as capas e lançando pó para o ar,");
    b->dados[ATOS].capitulos[22].versos[24] = wxT("o comandante mandou que levassem Paulo para dentro da fortaleza, ordenando que fosse interrogado debaixo de açoites, para saber por que causa assim clamavam contra ele.");
    b->dados[ATOS].capitulos[22].versos[25] = wxT("Quando o haviam atado com as correias, disse Paulo ao centurião que ali estava: É-vos lícito açoitar um cidadão romano, sem ser ele condenado?");
    b->dados[ATOS].capitulos[22].versos[26] = wxT("Ouvindo isto, foi o centurião ter com o comandante e o avisou, dizendo: Vê o que estás para fazer, pois este homem é romano.");
    b->dados[ATOS].capitulos[22].versos[27] = wxT("Vindo o comandante, perguntou-lhe: Dize-me: és tu romano? Respondeu ele: Sim sou.");
    b->dados[ATOS].capitulos[22].versos[28] = wxT("Tornou o comandante: Eu por grande soma de dinheiro adquiri este direito de cidadão. Paulo disse: Mas eu o sou de nascimento.");
    b->dados[ATOS].capitulos[22].versos[29] = wxT("Imediatamente, pois se apartaram dele aqueles que o iam interrogar; e até o comandante, tendo sabido que Paulo era romano, atemorizou-se porque o havia ligado.");
    b->dados[ATOS].capitulos[22].versos[30] = wxT("No dia seguinte, querendo saber ao certo a causa por que ele era acusado pelos judeus, soltou-o das prisões, e mandou que se reunissem os principais sacerdotes e todo o sinédrio; e, trazendo Paulo, apresentou-o diante deles.");

    b->dados[ATOS].capitulos[23].versos[1] = wxT("Fitando Paulo os olhos no sinédrio, disse: Varões irmãos, até o dia de hoje tenho andado diante de Deus com toda a boa consciência.");
    b->dados[ATOS].capitulos[23].versos[2] = wxT("Mas o sumo sacerdote, Ananias, mandou aos que estavam junto dele que o ferissem na boca.");
    b->dados[ATOS].capitulos[23].versos[3] = wxT("Então Paulo lhe disse: Deus te ferirá a ti, parede branqueada; tu estás aí sentado para julgar-me segundo a lei, e contra a lei mandas que eu seja ferido?");
    b->dados[ATOS].capitulos[23].versos[4] = wxT("Os que estavam ali disseram: Injurias o sumo sacerdote de Deus?");
    b->dados[ATOS].capitulos[23].versos[5] = wxT("Disse Paulo: Não sabia, irmãos, que era o sumo sacerdote; porque está escrito: Não dirás mal do príncipe do teu povo.");
    b->dados[ATOS].capitulos[23].versos[6] = wxT("Sabendo Paulo que uma parte era de saduceus e outra de fariseus, clamou no sinédrio: Varões irmãos, eu sou fariseu, filho de fariseus; é por causa da esperança da ressurreição dos mortos que estou sendo julgado.");
    b->dados[ATOS].capitulos[23].versos[7] = wxT("Ora, dizendo ele isto, surgiu dissensão entre os fariseus e saduceus; e a multidão se dividiu.");
    b->dados[ATOS].capitulos[23].versos[8] = wxT("Porque os saduceus dizem que não há ressurreição, nem anjo, nem espírito; mas os fariseus reconhecem uma e outra coisa.");
    b->dados[ATOS].capitulos[23].versos[9] = wxT("Daí procedeu grande clamor; e levantando-se alguns da parte dos fariseus, altercavam, dizendo: Não achamos nenhum mal neste homem. E se algum espírito ou anjo lhe falou, não resistamos a Deus.");
    b->dados[ATOS].capitulos[23].versos[10] = wxT("E avolumando-se a dissenção, o comandante, temendo que Paulo fosse por eles despedaçado, mandou que os soldados descessem e o tirassem do meio deles e o levassem para a fortaleza.");
    b->dados[ATOS].capitulos[23].versos[11] = wxT("Na noite seguinte, apresentou-se-lhe o Senhor e disse: Tem bom ânimo: porque, como deste testemunho de mim em Jerusalém, assim importa que o dês também em Roma.");
    b->dados[ATOS].capitulos[23].versos[12] = wxT("Quando já era dia, coligaram-se os judeus e juraram sob pena de maldição que não comeriam nem beberiam enquanto não matassem a Paulo.");
    b->dados[ATOS].capitulos[23].versos[13] = wxT("Eram mais de quarenta os que fizeram esta conjuração;");
    b->dados[ATOS].capitulos[23].versos[14] = wxT("e estes foram ter com os principais sacerdotes e anciãos, e disseram: Conjuramo-nos sob pena de maldição a não provarmos coisa alguma até que matemos a Paulo.");
    b->dados[ATOS].capitulos[23].versos[15] = wxT("Agora, pois, vós, com o sinédrio, rogai ao comandante que o mande descer perante vós como se houvésseis de examinar com mais precisão a sua causa; e nós estamos prontos para matá-lo antes que ele chegue.");
    b->dados[ATOS].capitulos[23].versos[16] = wxT("Mas o filho da irmã de Paulo, tendo sabido da cilada, foi, entrou na fortaleza e avisou a Paulo.");
    b->dados[ATOS].capitulos[23].versos[17] = wxT("Chamando Paulo um dos centuriões, disse: Leva este moço ao comandante, porque tem alguma coisa que lhe comunicar.");
    b->dados[ATOS].capitulos[23].versos[18] = wxT("Tomando-o ele, pois, levou-o ao comandante e disse: O preso Paulo, chamando-me, pediu-me que trouxesse à tua presença este moço, que tem alguma coisa a dizer-te.");
    b->dados[ATOS].capitulos[23].versos[19] = wxT("O comandante tomou-o pela mão e, retirando-se à parte, perguntou-lhe em particular: Que é que tens a contar-me?");
    b->dados[ATOS].capitulos[23].versos[20] = wxT("Disse ele: Os judeus combinaram rogar-te que amanhã mandes Paulo descer ao sinédrio, como que tendo de inquirir com mais precisão algo a seu respeito.");
    b->dados[ATOS].capitulos[23].versos[21] = wxT("Tu, pois, não te deixes persuadir por eles; porque mais de quarenta homens dentre eles armaram ciladas, os quais juraram sob pena de maldição não comerem nem beberem até que o tenham morto; e agora estão aprestados, esperando a tua promessa.");
    b->dados[ATOS].capitulos[23].versos[22] = wxT("Então o comandante despediu o moço, ordenando-lhe que a ninguém dissesse que lhe havia contado aquilo.");
    b->dados[ATOS].capitulos[23].versos[23] = wxT("Chamando dois centuriões, disse: Aprontai para a terceira hora da noite duzentos soldados de infantaria, setenta de cavalaria e duzentos lanceiros para irem até Cesaréia.");
    b->dados[ATOS].capitulos[23].versos[24] = wxT("E mandou que aparelhassem cavalgaduras para que Paulo montasse, a fim de o levarem salvo ao governador Félix.");
    b->dados[ATOS].capitulos[23].versos[25] = wxT("E escreveu-lhe uma carta nestes termos:");
    b->dados[ATOS].capitulos[23].versos[26] = wxT("Cláudio Lísias, ao excelentíssimo governador Félix, saúde.");
    b->dados[ATOS].capitulos[23].versos[27] = wxT("Este homem foi preso pelos judeus, e estava a ponto de ser morto por eles quando eu sobrevim com a tropa e o livrei ao saber que era romano.");
    b->dados[ATOS].capitulos[23].versos[28] = wxT("Querendo saber a causa por que o acusavam, levei-o ao sinédrio deles;");
    b->dados[ATOS].capitulos[23].versos[29] = wxT("e achei que era acusado de questões da lei deles, mas que nenhum crime havia nele digno de morte ou prisão.");
    b->dados[ATOS].capitulos[23].versos[30] = wxT("E quando fui informado que haveria uma cilada contra o homem, logo to enviei, intimando também aos acusadores que perante ti se manifestem contra ele. Passa bem.");
    b->dados[ATOS].capitulos[23].versos[31] = wxT("Os soldados, pois, conforme lhes fora mandado, tomando a Paulo, o levaram de noite a Antipátride.");
    b->dados[ATOS].capitulos[23].versos[32] = wxT("Mas no dia seguinte, deixando aos de cavalaria irem com ele, voltaram à fortaleza;");
    b->dados[ATOS].capitulos[23].versos[33] = wxT("os quais, logo que chegaram a Cesaréia e entregaram a carta ao governador, apresentaram-lhe também Paulo.");
    b->dados[ATOS].capitulos[23].versos[34] = wxT("Tendo lido a carta, o governador perguntou de que província ele era; e, sabendo que era da Cilícia, disse:");
    b->dados[ATOS].capitulos[23].versos[35] = wxT("Ouvir-te-ei quando chegarem também os teus acusadores; e mandou que fosse guardado no pretório de Herodes.");

    b->dados[ATOS].capitulos[24].versos[1] = wxT("Cinco dias depois o sumo sacerdote Ananias desceu com alguns anciãos e um certo Tertulo, orador, os quais fizeram, perante o governador, queixa contra Paulo.");
    b->dados[ATOS].capitulos[24].versos[2] = wxT("Sendo este chamado, Tertulo começou a acusá-lo, dizendo:");
    b->dados[ATOS].capitulos[24].versos[3] = wxT("Visto que por ti gozamos de muita paz e por tua providência são continuamente feitas reformas nesta nação, em tudo e em todo lugar reconhecemo-lo com toda a gratidão, ó excelentíssimo Félix.");
    b->dados[ATOS].capitulos[24].versos[4] = wxT("Mas, para que não te detenha muito rogo-te que, conforme a tua eqüidade, nos ouças por um momento.");
    b->dados[ATOS].capitulos[24].versos[5] = wxT("Temos achado que este homem é uma peste, e promotor de sedições entre todos os judeus, por todo o mundo, e chefe da seita dos nazarenos;");
    b->dados[ATOS].capitulos[24].versos[6] = wxT("o qual tentou profanar o templo; e nós o prendemos, e conforme a nossa lei o quisemos julgar.");
    b->dados[ATOS].capitulos[24].versos[7] = wxT("Mas sobrevindo o comandante Lísias no-lo tirou dentre as mãos com grande violência,");
    b->dados[ATOS].capitulos[24].versos[8] = wxT("mandando aos acusadores que viessem a ti; e dele tu mesmo, examinando-o, poderás certificar-te de tudo aquilo de que o acusamos.");
    b->dados[ATOS].capitulos[24].versos[9] = wxT("Os judeus também concordam na acusação, afirmando que estas coisas eram assim.");
    b->dados[ATOS].capitulos[24].versos[10] = wxT("Paulo, tendo-lhe o governador feito sinal que falasse, respondeu: Porquanto sei que há muitos anos és juiz sobre esta nação, com bom ânimo faço a minha defesa,");
    b->dados[ATOS].capitulos[24].versos[11] = wxT("pois bem podes verificar que não há mais de doze dias subi a Jerusalém para adorar,");
    b->dados[ATOS].capitulos[24].versos[12] = wxT("e que não me acharam no templo discutindo com alguém nem amotinando o povo, quer nas sinagogas quer na cidade.");
    b->dados[ATOS].capitulos[24].versos[13] = wxT("Nem te podem provar as coisas de que agora me acusam.");
    b->dados[ATOS].capitulos[24].versos[14] = wxT("Mas confesso-te isto: que, seguindo o caminho a que eles chamam seita, assim sirvo ao Deus de nossos pais, crendo tudo quanto está escrito na lei e nos profetas.");
    b->dados[ATOS].capitulos[24].versos[15] = wxT("Tendo esperança em Deus, como estes mesmos também esperam, de que há de haver ressurreição tanto dos justos como dos injustos.");
    b->dados[ATOS].capitulos[24].versos[16] = wxT("Por isso procuro sempre ter uma consciência sem ofensas diante de Deus e dos homens.");
    b->dados[ATOS].capitulos[24].versos[17] = wxT("Vários anos depois vim trazer à minha nação esmolas e ofertas.");
    b->dados[ATOS].capitulos[24].versos[18] = wxT("Ocupado nestas coisas, me acharam já santificado no templo não em ajuntamento, nem com tumulto, alguns judeus da Ásia,");
    b->dados[ATOS].capitulos[24].versos[19] = wxT("os quais deviam comparecer diante de ti e acusar-me se tivessem alguma coisa contra mim;");
    b->dados[ATOS].capitulos[24].versos[20] = wxT("ou estes mesmos digam que iniqüidade acharam, quando compareci perante o sinédrio,");
    b->dados[ATOS].capitulos[24].versos[21] = wxT("a não ser acerca desta única palavra que, estando no meio deles, bradei: Por causa da ressurreição dos mortos é que hoje estou sendo julgado por vós.");
    b->dados[ATOS].capitulos[24].versos[22] = wxT("Félix, porém, que era bem informado a respeito do Caminho, adiou a questão, dizendo: Quando o comandante Lísias tiver descido, então tomarei inteiro conhecimento da vossa causa.");
    b->dados[ATOS].capitulos[24].versos[23] = wxT("E ordenou ao centurião que Paulo ficasse detido, mas fosse tratado com brandura e que a nenhum dos seus proibisse servi-lo.");
    b->dados[ATOS].capitulos[24].versos[24] = wxT("Alguns dias depois, vindo Félix com sua mulher Drusila, que era judia, mandou chamar a Paulo, e ouviu-o acerca da fé em Cristo Jesus.");
    b->dados[ATOS].capitulos[24].versos[25] = wxT("E discorrendo ele sobre a justiça, o domínio próprio e o juízo vindouro, Félix ficou atemorizado e respondeu: Por ora vai-te, e quando tiver ocasião favorável, eu te chamarei.");
    b->dados[ATOS].capitulos[24].versos[26] = wxT("Esperava ao mesmo tempo que Paulo lhe desse dinheiro, pelo que o mandava chamar mais freqüentemente e conversava com ele.");
    b->dados[ATOS].capitulos[24].versos[27] = wxT("Mas passados dois anos, teve Félix por sucessor a Pórcio Festo; e querendo Félix agradar aos judeus, deixou a Paulo preso.");

    b->dados[ATOS].capitulos[25].versos[1] = wxT("Tendo, pois, entrado Festo na província, depois de três dias subiu de Cesaréia a Jerusalém.");
    b->dados[ATOS].capitulos[25].versos[2] = wxT("E os principais sacerdotes e os mais eminentes judeus fizeram-lhe queixa contra Paulo e, em detrimento deste,");
    b->dados[ATOS].capitulos[25].versos[3] = wxT("lhe rogavam o favor de o mandar a Jerusalém, armando ciladas para o matarem no caminho.");
    b->dados[ATOS].capitulos[25].versos[4] = wxT("Mas Festo respondeu que Paulo estava detido em Cesaréia, e que ele mesmo brevemente partiria para lá.");
    b->dados[ATOS].capitulos[25].versos[5] = wxT("Portanto, disse ele às autoridades dentre vós desçam comigo e, se há nesse homem algum crime, acusem-no.");
    b->dados[ATOS].capitulos[25].versos[6] = wxT("Tendo-se demorado entre eles não mais de oito ou dez dias, desceu a Cesaréia; e no dia seguinte, sentando-se no tribunal, mandou trazer Paulo.");
    b->dados[ATOS].capitulos[25].versos[7] = wxT("Tendo ele comparecido, rodearam-no os judeus que haviam descido de Jerusalém, trazendo contra ele muitas e graves acusações, que não podiam provar.");
    b->dados[ATOS].capitulos[25].versos[8] = wxT("Paulo, porém, respondeu em sua defesa: Nem contra a lei dos judeus, nem contra o templo, nem contra César, tenho pecado em coisa alguma.");
    b->dados[ATOS].capitulos[25].versos[9] = wxT("Todavia Festo, querendo agradar aos judeus, respondendo a Paulo, disse: Queres subir a Jerusalém e ali ser julgado perante mim acerca destas coisas?");
    b->dados[ATOS].capitulos[25].versos[10] = wxT("Mas Paulo disse: Estou perante o tribunal de César, onde devo ser julgado; nenhum mal fiz aos judeus, como muito bem sabes.");
    b->dados[ATOS].capitulos[25].versos[11] = wxT("Se, pois, sou malfeitor e tenho cometido alguma coisa digna de morte, não recuso morrer; mas se nada há daquilo de que estes me acusam, ninguém me pode entregar a eles; apelo para César.");
    b->dados[ATOS].capitulos[25].versos[12] = wxT("Então Festo, tendo falado com o conselho, respondeu: Apelaste para César; para César irás.");
    b->dados[ATOS].capitulos[25].versos[13] = wxT("Passados alguns dias, o rei Agripa e Berenice vieram a Cesaréia em visita de saudação a Festo.");
    b->dados[ATOS].capitulos[25].versos[14] = wxT("E, como se demorassem ali muitos dias, Festo expôs ao rei o caso de Paulo, dizendo: Há aqui certo homem que foi deixado preso por Félix,");
    b->dados[ATOS].capitulos[25].versos[15] = wxT("a respeito do qual, quando estive em Jerusalém, os principais sacerdotes e os anciãos dos judeus me fizeram queixas, pedindo sentença contra ele;");
    b->dados[ATOS].capitulos[25].versos[16] = wxT("aos quais respondi que não é costume dos romanos condenar homem algum sem que o acusado tenha presentes os seus acusadores e possa defender-se da acusação.");
    b->dados[ATOS].capitulos[25].versos[17] = wxT("Quando então eles se haviam reunido aqui, sem me demorar, no dia seguinte sentei-me no tribunal e mandei trazer o homem;");
    b->dados[ATOS].capitulos[25].versos[18] = wxT("contra o qual os acusadores, levantando-se, não apresentaram acusação alguma das coisas perversas que eu suspeitava;");
    b->dados[ATOS].capitulos[25].versos[19] = wxT("tinham, porém, contra ele algumas questões acerca da sua religião e de um tal Jesus defunto, que Paulo afirmava estar vivo.");
    b->dados[ATOS].capitulos[25].versos[20] = wxT("E, estando eu perplexo quanto ao modo de investigar estas coisas, perguntei se não queria ir a Jerusalém e ali ser julgado no tocante às mesmas.");
    b->dados[ATOS].capitulos[25].versos[21] = wxT("Mas apelando Paulo para que fosse reservado ao julgamento do imperador, mandei que fosse detido até que o enviasse a César.");
    b->dados[ATOS].capitulos[25].versos[22] = wxT("Então Agripa disse a Festo: Eu bem quisera ouvir esse homem. Respondeu-lhe ele: Amanhã o ouvirás.");
    b->dados[ATOS].capitulos[25].versos[23] = wxT("No dia seguinte vindo Agripa e Berenice, com muito aparato, entraram no auditório com os chefes militares e homens principais da cidade; então, por ordem de Festo, Paulo foi trazido.");
    b->dados[ATOS].capitulos[25].versos[24] = wxT("Disse Festo: Rei Agripa e vós todos que estais presentes conosco, vedes este homem por causa de quem toda a multidão dos judeus, tanto em Jerusalém como aqui, recorreu a mim, clamando que não convinha que ele vivesse mais.");
    b->dados[ATOS].capitulos[25].versos[25] = wxT("Eu, porém, achei que ele não havia praticado coisa alguma digna de morte; mas havendo ele apelado para o imperador, resolvi remeter-lho.");
    b->dados[ATOS].capitulos[25].versos[26] = wxT("Do qual não tenho coisa certa que escreva a meu senhor, e por isso perante vós o trouxe, principalmente perante ti, ó rei Agripa, para que, depois de feito o interrogatório, tenha eu alguma coisa que escrever.");
    b->dados[ATOS].capitulos[25].versos[27] = wxT("Porque não me parece razoável enviar um preso, e não notificar as acusações que há contra ele.");

    b->dados[ATOS].capitulos[26].versos[1] = wxT("Depois Agripa disse a Paulo: É-te permitido fazer a tua defesa. Então Paulo, estendendo a mão, começou a sua defesa:");
    b->dados[ATOS].capitulos[26].versos[2] = wxT("Sinto-me feliz, ó rei Agripa, em poder defender-me hoje perante ti de todas as coisas de que sou acusado pelos judeus;");
    b->dados[ATOS].capitulos[26].versos[3] = wxT("mormente porque és versado em todos os costumes e questões que há entre os judeus; pelo que te rogo que me ouças com paciência.");
    b->dados[ATOS].capitulos[26].versos[4] = wxT("A minha vida, pois, desde a mocidade, o que tem sido sempre entre o meu povo e em Jerusalém, sabem-na todos os judeus,");
    b->dados[ATOS].capitulos[26].versos[5] = wxT("pois me conhecem desde o princípio e, se quiserem, podem dar testemunho de que, conforme a mais severa seita da nossa religião, vivi fariseu.");
    b->dados[ATOS].capitulos[26].versos[6] = wxT("E agora estou aqui para ser julgado por causa da esperança da promessa feita por Deus a nossos pais,");
    b->dados[ATOS].capitulos[26].versos[7] = wxT("a qual as nossas doze tribos, servindo a Deus fervorosamente noite e dia, esperam alcançar; é por causa desta esperança, ó rei, que eu sou acusado pelos judeus.");
    b->dados[ATOS].capitulos[26].versos[8] = wxT("Por que é que se julga entre vós incrível que Deus ressuscite os mortos?");
    b->dados[ATOS].capitulos[26].versos[9] = wxT("Eu, na verdade, cuidara que devia praticar muitas coisas contra o nome de Jesus, o nazareno;");
    b->dados[ATOS].capitulos[26].versos[10] = wxT("o que, com efeito, fiz em Jerusalém. Pois havendo recebido autoridade dos principais dos sacerdotes, não somente encerrei muitos dos santos em prisões, como também dei o meu voto contra eles quando os matavam.");
    b->dados[ATOS].capitulos[26].versos[11] = wxT("E, castigando-os muitas vezes por todas as sinagogas, obrigava-os a blasfemar; e enfurecido cada vez mais contra eles, perseguia-os até nas cidades estrangeiras.");
    b->dados[ATOS].capitulos[26].versos[12] = wxT("Indo com este encargo a Damasco, munido de poder e comissão dos principais sacerdotes,");
    b->dados[ATOS].capitulos[26].versos[13] = wxT("ao meio-dia, ó rei vi no caminho uma luz do céu, que excedia o esplendor do sol, resplandecendo em torno de mim e dos que iam comigo.");
    b->dados[ATOS].capitulos[26].versos[14] = wxT("E, caindo nós todos por terra, ouvi uma voz que me dizia em língua hebráica: Saulo, Saulo, por que me persegues? Dura coisa te é recalcitrar contra os aguilhões.");
    b->dados[ATOS].capitulos[26].versos[15] = wxT("Disse eu: Quem és, Senhor? Respondeu o Senhor: Eu sou Jesus, a quem tu persegues;");
    b->dados[ATOS].capitulos[26].versos[16] = wxT("mas levanta-te e põe-te em pé; pois para isto te apareci, para te fazer ministro e testemunha tanto das coisas em que me tens visto como daquelas em que te hei de aparecer;");
    b->dados[ATOS].capitulos[26].versos[17] = wxT("livrando-te deste povo e dos gentios, aos quais te envio,");
    b->dados[ATOS].capitulos[26].versos[18] = wxT("para lhes abrir os olhos a fim de que se convertam das trevas à luz, e do poder de Satanás a Deus, para que recebam remissão de pecados e herança entre aqueles que são santificados pela fé em mim.");
    b->dados[ATOS].capitulos[26].versos[19] = wxT("Pelo que, ó rei Agripa, não fui desobediente à visão celestial,");
    b->dados[ATOS].capitulos[26].versos[20] = wxT("antes anunciei primeiramente aos que estão em Damasco, e depois em Jerusalém, e por toda a terra da Judéia e também aos gentios, que se arrependessem e se convertessem a Deus, praticando obras dignas de arrependimento.");
    b->dados[ATOS].capitulos[26].versos[21] = wxT("Por causa disto os judeus me prenderam no templo e procuravam matar-me.");
    b->dados[ATOS].capitulos[26].versos[22] = wxT("Tendo, pois, alcançado socorro da parte de Deus, ainda até o dia de hoje permaneço, dando testemunho tanto a pequenos como a grandes, não dizendo nada senão o que os profetas e Moisés disseram que devia acontecer;");
    b->dados[ATOS].capitulos[26].versos[23] = wxT("isto é, como o Cristo devia padecer, e como seria ele o primeiro que, pela ressurreição dos mortos, devia anunciar a luz a este povo e também aos gentios.");
    b->dados[ATOS].capitulos[26].versos[24] = wxT("Fazendo ele deste modo a sua defesa, disse Festo em alta voz: Estás louco, Paulo; as muitas letras te fazem delirar.");
    b->dados[ATOS].capitulos[26].versos[25] = wxT("Mas Paulo disse: Não deliro, ó excelentíssimo Festo, antes digo palavras de verdade e de perfeito juízo.");
    b->dados[ATOS].capitulos[26].versos[26] = wxT("Porque o rei, diante de quem falo com liberdade, sabe destas coisas, pois não creio que nada disto lhe é oculto; porque isto não se fez em qualquer canto.");
    b->dados[ATOS].capitulos[26].versos[27] = wxT("Crês tu nos profetas, ó rei Agripa? Sei que crês.");
    b->dados[ATOS].capitulos[26].versos[28] = wxT("Disse Agripa a Paulo: Por pouco me persuades a fazer-me cristão.");
    b->dados[ATOS].capitulos[26].versos[29] = wxT("Respondeu Paulo: Prouvera a Deus que, ou por pouco ou por muito, não somente tu, mas também todos quantos hoje me ouvem, se tornassem tais qual eu sou, menos estas cadeias.");
    b->dados[ATOS].capitulos[26].versos[30] = wxT("E levantou-se o rei, e o governador, e Berenice, e os que com eles estavam sentados,");
    b->dados[ATOS].capitulos[26].versos[31] = wxT("e retirando-se falavam uns com os outros, dizendo: Este homem não fez nada digno de morte ou prisão.");
    b->dados[ATOS].capitulos[26].versos[32] = wxT("Então Agripa disse a Festo: Este homem bem podia ser solto, se não tivesse apelado para César.");

    b->dados[ATOS].capitulos[27].versos[1] = wxT("E, como se determinou que navegássemos para a Itália, entregaram Paulo e alguns outros presos a um centurião por nome Júlio, da corte augusta.");
    b->dados[ATOS].capitulos[27].versos[2] = wxT("E, embarcando em um navio de Adramítio, que estava prestes a navegar em demanda dos portos pela costa da Ásia, fizemo-nos ao mar, estando conosco Aristarco, macedônio de Tessalônica.");
    b->dados[ATOS].capitulos[27].versos[3] = wxT("No dia seguinte chegamos a Sidom, e Júlio, tratando Paulo com bondade, permitiu-lhe ir ver os amigos e receber deles os cuidados necessários.");
    b->dados[ATOS].capitulos[27].versos[4] = wxT("Partindo dali, fomos navegando a sotavento de Chipre, porque os ventos eram contrários.");
    b->dados[ATOS].capitulos[27].versos[5] = wxT("Tendo atravessado o mar ao longo da Cilícia e Panfília, chegamos a Mirra, na Lícia.");
    b->dados[ATOS].capitulos[27].versos[6] = wxT("Ali o centurião achou um navio de Alexandria que navegava para a Itália, e nos fez embarcar nele.");
    b->dados[ATOS].capitulos[27].versos[7] = wxT("Navegando vagarosamente por muitos dias, e havendo chegado com dificuldade defronte de Cnido, não nos permitindo o vento ir mais adiante, navegamos a sotavento de Creta, à altura de Salmone;");
    b->dados[ATOS].capitulos[27].versos[8] = wxT("e, costeando-a com dificuldade, chegamos a um lugar chamado Bons Portos, perto do qual estava a cidade de Laséia.");
    b->dados[ATOS].capitulos[27].versos[9] = wxT("Havendo decorrido muito tempo e tendo-se tornado perigosa a navegação, porque já havia passado o jejum, Paulo os advertia,");
    b->dados[ATOS].capitulos[27].versos[10] = wxT("dizendo-lhes: Senhores, vejo que a viagem vai ser com avaria e muita perda não só para a carga e o navio, mas também para as nossas vidas.");
    b->dados[ATOS].capitulos[27].versos[11] = wxT("Mas o centurião dava mais crédito ao piloto e ao dono do navio do que às coisas que Paulo dizia.");
    b->dados[ATOS].capitulos[27].versos[12] = wxT("E não sendo o porto muito próprio para invernar, os mais deles foram de parecer que daí se fizessem ao mar para ver se de algum modo podiam chegar a Fênice, um porto de Creta que olha para o nordeste e para o sueste, para ali invernar.");
    b->dados[ATOS].capitulos[27].versos[13] = wxT("Soprando brandamente o vento sul, e supondo eles terem alcançado o que desejavam, levantaram ferro e iam costeando Creta bem de perto.");
    b->dados[ATOS].capitulos[27].versos[14] = wxT("Mas não muito depois desencadeou-se do lado da ilha um tufão de vento chamado euro-aquilão;");
    b->dados[ATOS].capitulos[27].versos[15] = wxT("e, sendo arrebatado o navio e não podendo navegar contra o vento, cedemos à sua força e nos deixávamos levar.");
    b->dados[ATOS].capitulos[27].versos[16] = wxT("Correndo a sota-vento de uma pequena ilha chamada Clauda, somente a custo pudemos segurar o batel,");
    b->dados[ATOS].capitulos[27].versos[17] = wxT("o qual recolheram, usando então os meios disponíveis para cingir o navio; e, temendo que fossem lançados na Sirte, arriaram os aparelhos e se deixavam levar.");
    b->dados[ATOS].capitulos[27].versos[18] = wxT("Como fôssemos violentamente açoitados pela tempestade, no dia seguinte começaram a alijar a carga ao mar.");
    b->dados[ATOS].capitulos[27].versos[19] = wxT("E ao terceiro dia, com as próprias mãos lançaram os aparelhos do navio.");
    b->dados[ATOS].capitulos[27].versos[20] = wxT("Não aparecendo por muitos dia nem sol nem estrelas, e sendo nós ainda batidos por grande tempestade, fugiu-nos afinal toda a esperança de sermos salvos.");
    b->dados[ATOS].capitulos[27].versos[21] = wxT("Havendo eles estado muito tempo sem comer, Paulo, pondo-se em pé no meio deles, disse: Senhores, devíeis ter-me ouvido e não ter partido de Creta, para evitar esta avaria e perda.");
    b->dados[ATOS].capitulos[27].versos[22] = wxT("E agora vos exorto a que tenhais bom ânimo, pois não se perderá vida alguma entre vós, mas somente o navio.");
    b->dados[ATOS].capitulos[27].versos[23] = wxT("Porque esta noite me apareceu um anjo do Deus de quem eu sou e a quem sirvo,");
    b->dados[ATOS].capitulos[27].versos[24] = wxT("dizendo: Não temas, Paulo, importa que compareças perante César, e eis que Deus te deu todos os que navegam contigo.");
    b->dados[ATOS].capitulos[27].versos[25] = wxT("Portanto, senhores, tende bom ânimo; pois creio em Deus que há de suceder assim como me foi dito.");
    b->dados[ATOS].capitulos[27].versos[26] = wxT("Contudo é necessário irmos dar em alguma ilha.");
    b->dados[ATOS].capitulos[27].versos[27] = wxT("Quando chegou a décima quarta noite, sendo nós ainda impelidos pela tempestade no mar de Ádria, pela meia-noite, suspeitaram os marinheiros a proximidade de terra;");
    b->dados[ATOS].capitulos[27].versos[28] = wxT("e lançando a sonda, acharam vinte braças; passando um pouco mais adiante, e tornando a lançar a sonda, acharam quinze braças.");
    b->dados[ATOS].capitulos[27].versos[29] = wxT("Ora, temendo irmos dar em rochedos, lançaram da popa quatro âncoras, e esperaram ansiosos que amanhecesse.");
    b->dados[ATOS].capitulos[27].versos[30] = wxT("Procurando, entrementes, os marinheiros fugir do navio, e tendo arriado o batel ao mar sob pretexto de irem lançar âncoras pela proa,");
    b->dados[ATOS].capitulos[27].versos[31] = wxT("disse Paulo ao centurião e aos soldados: Se estes não ficarem no navio, não podereis salvar-vos.");
    b->dados[ATOS].capitulos[27].versos[32] = wxT("Então os soldados cortaram os cabos do batel e o deixaram cair.");
    b->dados[ATOS].capitulos[27].versos[33] = wxT("Enquanto amanhecia, Paulo rogava a todos que comessem alguma coisa, dizendo: É já hoje o décimo quarto dia que esperais e permaneceis em jejum, não havendo provado coisa alguma.");
    b->dados[ATOS].capitulos[27].versos[34] = wxT("Rogo-vos, portanto, que comais alguma coisa, porque disso depende a vossa segurança; porque nem um cabelo cairá da cabeça de qualquer de vós.");
    b->dados[ATOS].capitulos[27].versos[35] = wxT("E, havendo dito isto, tomou o pão, deu graças a Deus na presença de todos e, partindo-o começou a comer.");
    b->dados[ATOS].capitulos[27].versos[36] = wxT("Então todos cobraram ânimo e se puseram também a comer.");
    b->dados[ATOS].capitulos[27].versos[37] = wxT("Éramos ao todo no navio duzentas e setenta e seis almas.");
    b->dados[ATOS].capitulos[27].versos[38] = wxT("Depois de saciados com a comida, começaram a aliviar o navio, alijando o trigo no mar.");
    b->dados[ATOS].capitulos[27].versos[39] = wxT("Quando amanheceu, não reconheciam a terra; divisavam, porém, uma enseada com uma praia, e consultavam se poderiam nela encalhar o navio.");
    b->dados[ATOS].capitulos[27].versos[40] = wxT("Soltando as âncoras, deixaram-nas no mar, largando ao mesmo tempo as amarras do leme; e, içando ao vento a vela da proa, dirigiram-se para a praia.");
    b->dados[ATOS].capitulos[27].versos[41] = wxT("Dando, porém, num lugar onde duas correntes se encontravam, encalharam o navio; e a proa, encravando-se, ficou imóvel, mas a popa se desfazia com a força das ondas.");
    b->dados[ATOS].capitulos[27].versos[42] = wxT("Então o parecer dos soldados era que matassem os presos para que nenhum deles fugisse, escapando a nado.");
    b->dados[ATOS].capitulos[27].versos[43] = wxT("Mas o centurião, querendo salvar a Paulo, estorvou-lhes este intento; e mandou que os que pudessem nadar fossem os primeiros a lançar-se ao mar e alcançar a terra;");
    b->dados[ATOS].capitulos[27].versos[44] = wxT("e que os demais se salvassem, uns em tábuas e outros em quaisquer destroços do navio. Assim chegaram todos à terra salvos.");

    b->dados[ATOS].capitulos[28].versos[1] = wxT("Estando já salvos, soubemos então que a ilha se chamava Malta.");
    b->dados[ATOS].capitulos[28].versos[2] = wxT("Os indígenas usaram conosco de não pouca humanidade; pois acenderam uma fogueira e nos recolheram a todos por causa da chuva que caía, e por causa do frio.");
    b->dados[ATOS].capitulos[28].versos[3] = wxT("Ora havendo Paulo ajuntado e posto sobre o fogo um feixe de gravetos, uma víbora, fugindo do calor, apegou-se-lhe à mão.");
    b->dados[ATOS].capitulos[28].versos[4] = wxT("Quando os indígenas viram o réptil pendente da mão dele, diziam uns aos outros: Certamente este homem é homicida, pois, embora salvo do mar, a Justiça não o deixa viver.");
    b->dados[ATOS].capitulos[28].versos[5] = wxT("Mas ele, sacudindo o réptil no fogo, não sofreu mal nenhum.");
    b->dados[ATOS].capitulos[28].versos[6] = wxT("Eles, porém, esperavam que Paulo viesse a inchar ou a cair morto de repente; mas tendo esperado muito tempo e vendo que nada de anormal lhe sucedia, mudaram de parecer e diziam que era um deus.");
    b->dados[ATOS].capitulos[28].versos[7] = wxT("Ora, nos arredores daquele lugar havia umas terras que pertenciam ao homem principal da ilha, por nome Públio, o qual nos recebeu e hospedou bondosamente por três dias.");
    b->dados[ATOS].capitulos[28].versos[8] = wxT("Aconteceu estar de cama, enfermo de febre e disenteria, o pai de Públio; Paulo foi visitá-lo, e havendo orado, impôs-lhe as mãos, e o curou.");
    b->dados[ATOS].capitulos[28].versos[9] = wxT("Feito isto, vinham também os demais enfermos da ilha, e eram curados;");
    b->dados[ATOS].capitulos[28].versos[10] = wxT("e estes nos distinguiram com muitas honras; e, ao embarcarmos, puseram a bordo as coisas que nos eram necessárias.");
    b->dados[ATOS].capitulos[28].versos[11] = wxT("Passados três meses, partimos em um navio de Alexandria que invernara na ilha, o qual tinha por insígnia Castor e Pólux.");
    b->dados[ATOS].capitulos[28].versos[12] = wxT("E chegando a Siracusa, ficamos ali três dias;");
    b->dados[ATOS].capitulos[28].versos[13] = wxT("donde, costeando, viemos a Régio; e, soprando no dia seguinte o vento sul, chegamos em dois dias a Putéoli,");
    b->dados[ATOS].capitulos[28].versos[14] = wxT("onde, achando alguns irmãos, fomos convidados a ficar com eles sete dias; e depois nos dirigimos a Roma.");
    b->dados[ATOS].capitulos[28].versos[15] = wxT("Ora, os irmãos da lá, havendo recebido notícias nossas, vieram ao nosso encontro até a praça de Ápio e às Três Vendas, e Paulo, quando os viu, deu graças a Deus e cobrou ânimo.");
    b->dados[ATOS].capitulos[28].versos[16] = wxT("Quando chegamos a Roma, {o centurião entregou os presos ao general do exército, mas,} a Paulo se lhe permitiu morar à parte, com o soldado que o guardava.");
    b->dados[ATOS].capitulos[28].versos[17] = wxT("Passados três dias, ele convocou os principais dentre os judeus; e reunidos eles, disse-lhes: Varões irmãos, não havendo eu feito nada contra o povo, ou contra os ritos paternos, vim contudo preso desde Jerusalém, entregue nas mãos dos romanos;");
    b->dados[ATOS].capitulos[28].versos[18] = wxT("os quais, havendo-me interrogado, queriam soltar-me, por não haver em mim crime algum que merecesse a morte.");
    b->dados[ATOS].capitulos[28].versos[19] = wxT("Mas opondo-se a isso os judeus, vi-me obrigado a apelar para César, não tendo, contudo, nada de que acusar a minha nação.");
    b->dados[ATOS].capitulos[28].versos[20] = wxT("Por esta causa, pois, vos convidei, para vos ver e falar; porque pela esperança de Israel estou preso com esta cadeia.");
    b->dados[ATOS].capitulos[28].versos[21] = wxT("Mas eles lhe disseram: Nem recebemos da Judéia cartas a teu respeito, nem veio aqui irmão algum que contasse ou dissesse mal de ti.");
    b->dados[ATOS].capitulos[28].versos[22] = wxT("No entanto bem quiséramos ouvir de ti o que pensas; porque, quanto a esta seita, notório nos é que em toda parte é impugnada.");
    b->dados[ATOS].capitulos[28].versos[23] = wxT("Havendo-lhe eles marcado um dia, muitos foram ter com ele à sua morada, aos quais desde a manhã até a noite explicava com bom testemunho o reino de Deus e procurava persuadí-los acerca de Jesus, tanto pela lei de Moisés como pelos profetas.");
    b->dados[ATOS].capitulos[28].versos[24] = wxT("Uns criam nas suas palavras, mas outros as rejeitavam.");
    b->dados[ATOS].capitulos[28].versos[25] = wxT("E estando discordes entre si, retiraram-se, havendo Paulo dito esta palavra: Bem falou o Espírito Santo aos vossos pais pelo profeta Isaías,");
    b->dados[ATOS].capitulos[28].versos[26] = wxT("dizendo: Vai a este povo e dize: Ouvindo, ouvireis, e de maneira nenhuma entendereis; e vendo, vereis, e de maneira nenhuma percebereis.");
    b->dados[ATOS].capitulos[28].versos[27] = wxT("Porque o coração deste povo se endureceu, e com os ouvidos ouviram tardamente, e fecharam os olhos; para que não vejam com os olhos, nem ouçam com os ouvidos, nem entendam com o coração nem se convertam e eu os cure.");
    b->dados[ATOS].capitulos[28].versos[28] = wxT("Seja-vos pois notório que esta salvação de Deus é enviada aos gentios, e eles ouvirão.");
    b->dados[ATOS].capitulos[28].versos[29] = wxT("{E, havendo ele dito isto, partiram os judeus, tendo entre si grande contenda.}");
    b->dados[ATOS].capitulos[28].versos[30] = wxT("E morou dois anos inteiros na casa que alugara, e recebia a todos os que o visitavam,");
    b->dados[ATOS].capitulos[28].versos[31] = wxT("pregando o reino de Deus e ensinando as coisas concernentes ao Senhor Jesus Cristo, com toda a liberdade, sem impedimento algum.");

}
